import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { supabase, supabaseSafe, resetRateLimiters } from '../lib/supabaseSafe';
import { useAuth } from './AuthContext';
import type { Note } from '../types/note';

interface NotesContextType {
    notes: Note[];
    stats: { totalBy: number; favorites: number };
    loading: boolean;
    canCreateNote: boolean;
    refreshNotes: (searchTerm?: string, sortBy?: string) => Promise<void>;
}

const NotesContext = createContext<NotesContextType | undefined>(undefined);

export const NotesProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, isPro } = useAuth();
    const [notes, setNotes] = useState<Note[]>([]);
    const [stats, setStats] = useState({ totalBy: 0, favorites: 0 });
    const [loading, setLoading] = useState(true);

    const canCreateNote = isPro || stats.totalBy < 100;

    /**
     * Fetch notes from the database with caching and rate-limiting.
     */
    const fetchNotes = useCallback(async (searchTerm = '', sortBy = 'latest') => {
        if (!user) return;

        try {
            // Using a unique key per user/search/sort configuration for the cache
            const results = await supabaseSafe<Note[]>(
                `notes-list-${user.id}-${searchTerm}-${sortBy}`,
                async () => {
                    let query = supabase
                        .from('notes')
                        .select('*')
                        .eq('owner_id', user.id);

                    if (sortBy === 'latest') query = query.order('updated_at', { ascending: false });
                    else if (sortBy === 'oldest') query = query.order('updated_at', { ascending: true });
                    else if (sortBy === 'title') query = query.order('title', { ascending: true });

                    if (searchTerm) {
                        query.ilike('title', `%${searchTerm}%`);
                    }
                    return query;
                },
                { fallback: [] }
            );

            setNotes(results || []);

            // Also update stats if it's the main list fetch
            if (!searchTerm) {
                const [totalRes, favRes] = await Promise.all([
                    supabase
                      .from('notes')
                      .select('id', { count: 'exact', head: true })
                      .eq('owner_id', user.id),
                    supabase
                      .from('notes')
                      .select('id', { count: 'exact', head: true })
                      .eq('owner_id', user.id)
                      .eq('is_favorite', true)
                ]);
                setStats({
                    totalBy: totalRes.count || 0,
                    favorites: favRes.count || 0
                });
            }
        } catch (error) {
            console.error('[NotesContext] Error fetching notes:', error);
        } finally {
            setLoading(false);
        }
    }, [user]);

    /**
     * Real-time Synchronization
     * Listens for changes to the 'notes' table for the current user.
     */
    useEffect(() => {
        if (!user) {
            setNotes([]);
            setLoading(false);
            return;
        }

        // Initial fetch
        fetchNotes();

        // 1. Subscribe to changes for this user's notes
        const channel = supabase
            .channel(`notes-sync-${user.id}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'notes',
                    filter: `owner_id=eq.${user.id}`
                },
                (payload) => {
                    console.log('[NotesContext] Real-time activity detected:', payload.eventType);

                    // 2. Invalidate relevant caches in supabaseSafe
                    // This ensures the NEXT fetchNotes (e.g. after a search change) gets fresh data.
                    resetRateLimiters('notes-list-');

                    // 3. Update local state immediately (Optimistic UI)
                    if (payload.eventType === 'INSERT') {
                        const newNote = payload.new as Note;
                        setNotes(prev => {
                            if (prev.some(n => n.id === newNote.id)) return prev;
                            return [newNote, ...prev];
                        });
                        setStats(prev => ({ ...prev, totalBy: prev.totalBy + 1 }));
                    } else if (payload.eventType === 'UPDATE') {
                        const updatedNote = payload.new as Note;
                        setNotes(prev => prev.map(n => n.id === updatedNote.id ? updatedNote : n));

                        // Recalculate favorites if changed
                        if (payload.old.is_favorite !== payload.new.is_favorite) {
                            setStats(prev => ({ 
                                ...prev, 
                                favorites: payload.new.is_favorite ? prev.favorites + 1 : prev.favorites - 1 
                            }));
                        }
                    } else if (payload.eventType === 'DELETE') {
                        const deletedId = payload.old.id;
                        const wasFavorite = notes.find(n => n.id === deletedId)?.is_favorite;
                        setNotes(prev => prev.filter(n => n.id !== deletedId));
                        setStats(prev => ({ 
                            totalBy: Math.max(0, prev.totalBy - 1),
                            favorites: wasFavorite ? Math.max(0, prev.favorites - 1) : prev.favorites
                        }));
                    }
                }
            )
            .subscribe((status) => {
               if (status === 'SUBSCRIBED') {
                   console.log('[NotesContext] Real-time subscription active.');
               }
            });

        return () => {
            supabase.removeChannel(channel);
        };
    }, [user, fetchNotes]);

    return (
        <NotesContext.Provider value={{ notes, stats, loading, canCreateNote, refreshNotes: fetchNotes }}>
            {children}
        </NotesContext.Provider>
    );
};

export const useNotes = () => {
    const context = useContext(NotesContext);
    if (context === undefined) {
        throw new Error('useNotes must be used within a NotesProvider');
    }
    return context;
};

import React, { createContext, useEffect, useRef, useState, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useSocket } from './SocketContext';
import { toast, type Toast } from 'react-hot-toast';
import { API_URL } from '../lib/api';

interface Notification {
    id: string;
    receiver_id: string;
    sender_id?: string;
    type: string;
    title: string;
    message?: string;
    link?: string;
    is_read: boolean;
    created_at: string;
    sender?: {
        username: string;
        avatar_url: string;
    };
    status?: string;
}

export interface NotificationContextValue {
    notifications: Notification[];
    loading: boolean;
    unreadCount: number;
    markAsRead: (id: string) => Promise<void>;
    markAllAsRead: () => Promise<void>;
    deleteNotification: (id: string) => Promise<void>;
    clearAllNotifications: () => Promise<void>;
}

export const NotificationContext = createContext<NotificationContextValue | null>(null);

export const NotificationProvider = ({ children }: { children: React.ReactNode }) => {
    const { session, authReady } = useAuth();
    const { socket, connected } = useSocket();
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [loading, setLoading] = useState(true);

    const isMounted = useRef(true);
    const notificationsFetchRef = useRef(false);
    const pushSubscribeRef = useRef(false);

    const unreadCount = notifications.filter(n => !n.is_read).length;

    const fetchNotifications = useCallback(async () => {
        if (!session || notificationsFetchRef.current) return;
        notificationsFetchRef.current = true;
        
        try {
            const res = await fetch(`${API_URL}/api/notifications`, {
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
            
            if (res.ok) {
                const data = await res.json();
                if (isMounted.current) setNotifications(data);
            }
        } catch (err) {
            console.error('[Notifications] Fetch failed:', err);
        } finally {
            if (isMounted.current) setLoading(false);
            notificationsFetchRef.current = false;
        }
    }, [session?.access_token]);

    const subscribeToPush = useCallback(async () => {
        if (!session || pushSubscribeRef.current) return;
        if (!('serviceWorker' in navigator && 'PushManager' in window)) return;
        
        pushSubscribeRef.current = true;
        try {
            const registration = await navigator.serviceWorker.register('/sw.js');
            const permission = await Notification.requestPermission();

            if (permission === 'granted') {
                const subscription = await registration.pushManager.subscribe({
                    userVisibleOnly: true,
                    applicationServerKey: import.meta.env.VITE_VAPID_PUBLIC_KEY
                });

                await fetch(`${API_URL}/api/notifications/subscribe`, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'Authorization': `Bearer ${session.access_token}`
                    },
                    body: JSON.stringify({ subscription })
                });
            }
        } catch (err) {
            console.error('[Notifications] Push subscription failed:', err);
        } finally {
            pushSubscribeRef.current = false;
        }
    }, [session?.access_token]);

    // Initial Fetch
    useEffect(() => {
        isMounted.current = true;
        if (authReady) {
            if (session) {
                fetchNotifications();
                subscribeToPush();
            } else {
                setLoading(false);
            }
        }
        return () => { isMounted.current = false; };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [authReady, session?.access_token, fetchNotifications, subscribeToPush]);

    // Socket listeners
    useEffect(() => {
        if (!socket || !connected) return;

        const onNotification = (notification: Notification) => {
            if (!isMounted.current) return;
            
            setNotifications(prev => [notification, ...prev]);

            toast.custom((t: Toast) => (
                <div 
                    className={`${t.visible ? 'animate-enter' : 'animate-leave'} max-w-md w-full bg-[#1a1a1a] shadow-lg rounded-lg pointer-events-auto flex ring-1 ring-black ring-opacity-5 border border-white/10 cursor-pointer`}
                    onClick={() => {
                        markAsRead(notification.id);
                        toast.dismiss(t.id);
                    }}
                >
                    <div className="flex-1 w-0 p-4">
                        <div className="flex items-start">
                            <div className="ml-3 flex-1">
                                <p className="text-sm font-medium text-white">{notification.title}</p>
                                <p className="mt-1 text-sm text-gray-400">{notification.message}</p>
                            </div>
                        </div>
                    </div>
                    <div className="flex border-l border-white/10">
                        <button
                            onClick={(e) => {
                                e.stopPropagation();
                                toast.dismiss(t.id);
                            }}
                            className="w-full border border-transparent rounded-none rounded-r-lg p-4 flex items-center justify-center text-sm font-medium text-primary hover:text-primary/80 focus:outline-none"
                        >
                            Close
                        </button>
                    </div>
                </div>
            ), { duration: 4000 });
        };

        socket.on('notification', onNotification);
        return () => {
            socket.off('notification', onNotification);
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [socket, connected]);

    const markAsRead = async (id: string) => {
        if (!session) return;
        try {
            const res = await fetch(`${API_URL}/api/notifications/${id}/read`, {
                method: 'PATCH',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
            if (res.ok && isMounted.current) {
                setNotifications(prev => prev.map(n => n.id === id ? { ...n, is_read: true } : n));
            }
        } catch (err) {
            console.error('[Notifications] Failed to mark as read:', err);
        }
    };

    const markAllAsRead = async () => {
        if (!session) return;
        try {
            const res = await fetch(`${API_URL}/api/notifications/read-all`, {
                method: 'PATCH',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
            if (res.ok && isMounted.current) {
                setNotifications(prev => prev.map(n => ({ ...n, is_read: true })));
            }
        } catch (err) {
            console.error('[Notifications] Failed to mark all as read:', err);
        }
    };

    const deleteNotification = async (id: string) => {
        if (!session) return;
        try {
            const res = await fetch(`${API_URL}/api/notifications/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
            if (res.ok && isMounted.current) {
                setNotifications(prev => prev.filter(n => n.id !== id));
                toast.success('Notification deleted');
            }
        } catch (err) {
            console.error('[Notifications] Failed to delete:', err);
            toast.error('Failed to delete notification');
        }
    };

    const clearAllNotifications = async () => {
        if (!session) return;
        if (!window.confirm('Are you sure you want to clear all notifications?')) return;
        
        try {
            const res = await fetch(`${API_URL}/api/notifications`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });
            if (res.ok && isMounted.current) {
                setNotifications([]);
                toast.success('All notifications cleared');
            }
        } catch (err) {
            console.error('[Notifications] Failed to clear all:', err);
            toast.error('Failed to clear notifications');
        }
    };

    return (
        <NotificationContext.Provider value={{ 
            notifications, 
            unreadCount, 
            markAsRead, 
            markAllAsRead, 
            deleteNotification,
            clearAllNotifications,
            loading 
        }}>
            {children}
        </NotificationContext.Provider>
    );
};

// ====================================
// TEAM CHAT CONTEXT
// Real-time team collaboration with safety
// ====================================

import React, { createContext, useContext, useEffect, useRef, useState, useCallback } from 'react';
import { RealtimeChannel } from '@supabase/supabase-js';
import { supabase } from '../lib/supabaseSafe';
import { useAuth } from './AuthContext';
import toast from 'react-hot-toast';
import {
  getTeamMessages,
  sendMessage as apiSendMessage,
  markMessagesRead,
  getTeamMembers,
  shareNote as apiShareNote,
} from '../lib/teamsApi';
import type {
  TeamMessage,
  TeamMember,
  SendMessageRequest,
  ShareNoteRequest,
  RealtimePayload,
  TeamStats,
} from '../types/teams';

// ====================================
// CONTEXT TYPES
// ====================================

interface TeamChatContextValue {
  messages: TeamMessage[];
  members: TeamMember[];
  loading: boolean;
  connected: boolean;
  sendMessage: (content: string, metadata?: Record<string, any>, type?: import('../types/teams').MessageType) => Promise<void>;
  shareNote: (noteId: string, permission?: 'read' | 'edit') => Promise<void>;
  loadMoreMessages: () => Promise<void>;
  hasMore: boolean;
  deleteMessage: (messageId: string) => Promise<void>;
  editMessage: (messageId: string, content: string) => Promise<void>;
  clearChatHistory: () => Promise<void>;
  sendTypingStatus: (isTyping: boolean) => void;
  typingUsers: string[];
  teamStats: TeamStats | null;
  error: string | null;
}

const TeamChatContext = createContext<TeamChatContextValue>({
  messages: [],
  members: [],
  loading: true,
  connected: false,
  sendMessage: async () => {},
  shareNote: async () => {},
  loadMoreMessages: async () => {},
  hasMore: false,
  deleteMessage: async () => {},
  editMessage: async () => {},
  clearChatHistory: async () => {},
  sendTypingStatus: () => {},
  typingUsers: [],
  teamStats: null,
  error: null,
});

export const useTeamChat = () => useContext(TeamChatContext);

// ====================================
// PROVIDER PROPS
// ====================================

interface TeamChatProviderProps {
  teamId: string;
  children: React.ReactNode;
}

// ====================================
// EXPONENTIAL BACKOFF CONFIG
// ====================================

const BACKOFF_CONFIG = {
  initialDelay: 1000,
  maxDelay: 30000,
  maxRetries: 5,
};

// ====================================
// PROVIDER COMPONENT
// ====================================

export const TeamChatProvider: React.FC<TeamChatProviderProps> = ({ teamId, children }) => {
  const { user, profile, authReady } = useAuth();
  const [messages, setMessages] = useState<TeamMessage[]>([]);
  const [members, setMembers] = useState<TeamMember[]>([]);
  const [loading, setLoading] = useState(true);
  const [connected, setConnected] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const [typingUsers, setTypingUsers] = useState<string[]>([]);
  const [teamStats, setTeamStats] = useState<TeamStats | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Refs for lifecycle and safety
  const isMounted = useRef(true);
  const channelRef = useRef<RealtimeChannel | null>(null);
  const loadingRef = useRef(false);
  const sendCooldownRef = useRef(false);
  const retryCountRef = useRef(0);
  const retryTimeoutRef = useRef<any>(null);
  const lastMessageIdRef = useRef<string | null>(null);

  // ====================================
  // LOAD INITIAL DATA
  // ====================================

  const lastLoadedTeamId = useRef<string | null>(null);

  const loadInitialData = useCallback(async () => {
    if (loadingRef.current || !teamId || !user || !profile || !authReady) return;
    
    // If we already loaded this team and have data, only reload if forced or empty
    if (lastLoadedTeamId.current === teamId && messages.length > 0) return;

    loadingRef.current = true;
    setLoading(true);
    setError(null);
    lastLoadedTeamId.current = teamId;

    try {
      // Load in parallel for speed
      const [messagesData, membersData, statsData] = await Promise.all([
        getTeamMessages(teamId, 50),
        getTeamMembers(teamId),
        import('../lib/teamsApi').then(m => m.getTeamStats(teamId))
      ]);

      if (!isMounted.current) return;

      setMessages(messagesData);
      setMembers(membersData);
      setTeamStats(statsData);

      // Mark as read
      await markMessagesRead(teamId);

      if (messagesData.length < 50) {
        setHasMore(false);
      } else {
        setHasMore(true);
      }

      lastMessageIdRef.current =
        messagesData.length > 0 ? messagesData[messagesData.length - 1].id : null;
    } catch (err: any) {
      console.error('[TeamChat] Failed to load initial data:', err);
      if (isMounted.current) {
        setError('Failed to load chat. Please refresh.');
        toast.error('Failed to load chat');
      }
    } finally {
      loadingRef.current = false;
      if (isMounted.current) {
        setLoading(false);
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [teamId, user, profile, authReady, messages.length]);

  // ====================================
  // LOAD MORE MESSAGES (PAGINATION)
  // ====================================

  const loadMoreMessages = useCallback(async () => {
    if (loadingRef.current || !hasMore || messages.length === 0) return;

    loadingRef.current = true;

    try {
      const oldestMessage = messages[0];
      const olderMessages = await getTeamMessages(teamId, 50, oldestMessage.created_at);

      if (!isMounted.current) return;

      setMessages((prev) => [...olderMessages, ...prev]);

      if (olderMessages.length < 50) {
        setHasMore(false);
      }
    } catch (err) {
      console.error('[TeamChat] Failed to load more messages:', err);
      toast.error('Failed to load older messages');
    } finally {
      loadingRef.current = false;
    }
  }, [teamId, messages, hasMore]);

  // ====================================
  // DELETE MESSAGE
  // ====================================

  const deleteMessage = useCallback(async (messageId: string) => {
    if (!teamId) return;
    try {
      const { deleteTeamMessage } = await import('../lib/teamsApi');
      const success = await deleteTeamMessage(teamId, messageId);
      if (success && isMounted.current) {
        setMessages(prev => prev.filter(m => m.id !== messageId));
      }
    } catch (err) {
      console.error('[TeamChat] Failed to delete message:', err);
      toast.error('Failed to delete message');
    }
  }, [teamId]);

  const editMessage = useCallback(async (messageId: string, newContent: string) => {
    if (!teamId) return;
    
    // Optimistic update
    let oldContent = '';
    setMessages(prev => {
      const msg = prev.find(m => m.id === messageId);
      if (msg) oldContent = msg.content || '';
      return prev.map(m => m.id === messageId ? { ...m, content: newContent, is_edited: true, updated_at: new Date().toISOString() } : m);
    });

    try {
      const { editTeamMessage } = await import('../lib/teamsApi');
      const success = await editTeamMessage(teamId, messageId, newContent);
      if (!success) {
        throw new Error('Failed to edit team message');
      }
    } catch (err) {
      console.error('[TeamChat] Editing message failed:', err);
      // Rollback
      if (oldContent) {
        setMessages(prev => prev.map(m => m.id === messageId ? { ...m, content: oldContent, is_edited: false } : m));
      }
      toast.error('Failed to edit message');
    }
  }, [teamId]);

  const clearChatHistory = useCallback(async () => {
    if (!teamId) return;
    try {
      const { clearTeamChatHistory } = await import('../lib/teamsApi');
      const success = await clearTeamChatHistory(teamId);
      if (success && isMounted.current) {
        setMessages([]);
        toast.success('Chat history cleared');
      }
    } catch (err) {
      console.error('[TeamChat] Failed to clear chat history:', err);
      toast.error('Failed to clear chat history');
    }
  }, [teamId]);

  // ====================================
  // SEND MESSAGE (WITH OPTIMISTIC UI)
  // ====================================

  const sendMessage = useCallback(
    async (content: string, metadata?: Record<string, any>, type: import('../types/teams').MessageType = 'text') => {
      if (!user || (!content.trim() && !metadata?.image_url && !metadata?.audio_url)) return;

      // Cooldown check (prevent spam)
      if (sendCooldownRef.current) {
        toast.error('Please wait before sending another message');
        return;
      }

      sendCooldownRef.current = true;
      setTimeout(() => {
        sendCooldownRef.current = false;
      }, 1000); // 1s cooldown

      // Optimistic message
      const optimisticId = `temp-${Date.now()}`;
      const optimisticMessage: TeamMessage = {
        id: optimisticId,
        team_id: teamId,
        sender_id: user.id,
        content,
        message_type: type,
        metadata: metadata ?? {},
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
        is_deleted: false,
        isOwn: true,
        isOptimistic: true,
        sender: {
          id: user.id,
          email: user.email ?? '',
          username: user.user_metadata?.username,
          full_name: user.user_metadata?.full_name,
          avatar_url: user.user_metadata?.avatar_url,
        },
      };

      // Add optimistically
      setMessages((prev) => [...prev, optimisticMessage]);

      try {
        const req: SendMessageRequest = {
          content,
          message_type: type,
          metadata,
        };

        const result = await apiSendMessage(teamId, req);

        if (!result) throw new Error('Failed to send message');

        // Replace optimistic with real (realtime will handle this, but fallback)
        if (!isMounted.current) return;
        
        setMessages((prev) =>
          prev.map((msg) => (msg.id === optimisticId ? { ...result, isOwn: true } : msg))
        );
      } catch (err: any) {
        console.error('[TeamChat] Failed to send message:', err);

        // Mark optimistic message as failed
        if (isMounted.current) {
          setMessages((prev) =>
            prev.map((msg) => (msg.id === optimisticId ? { ...msg, failed: true } : msg))
          );
          toast.error('Failed to send message');
        }
      }
    },
    [teamId, user]
  );

  // ====================================
  // SHARE NOTE
  // ====================================

  const shareNote = useCallback(
    async (noteId: string, permission: 'read' | 'edit' = 'read') => {
      try {
        const req: ShareNoteRequest = {
          note_id: noteId,
          permission,
        };

        const result = await apiShareNote(teamId, req);

        if (!result) throw new Error('Failed to share note');

        toast.success('Note shared successfully');
      } catch (err: any) {
        console.error('[TeamChat] Failed to share note:', err);
        toast.error(err.message || 'Failed to share note');
      }
    },
    [teamId]
  );
  
  // ====================================
  // TYPING INDICATORS (BROADCAST)
  // ====================================
  
  const typingTimersRef = useRef<Record<string, any>>({});

  const sendTypingStatus = useCallback((isTyping: boolean) => {
    if (!channelRef.current || !user || !profile) return;
    
    channelRef.current.send({
      type: 'broadcast',
      event: 'user_typing',
      payload: { 
        userId: user.id, 
        userName: profile.full_name || profile.username || 'Someone',
        isTyping 
      }
    });
  }, [user, profile]);

  // Handler for typing events
  const handleTypingEvent = useCallback((payload: any) => {
    const { userId, userName, isTyping } = payload;
    if (userId === user?.id) return;

    if (isTyping) {
      setTypingUsers(prev => prev.includes(userName) ? prev : [...prev, userName]);
      
      // Auto-clear after 5 seconds if no 'stop' received
      if (typingTimersRef.current[userId]) {
        clearTimeout(typingTimersRef.current[userId]);
      }
      typingTimersRef.current[userId] = setTimeout(() => {
        setTypingUsers(prev => prev.filter(u => u !== userName));
      }, 5000);
    } else {
      if (typingTimersRef.current[userId]) {
        clearTimeout(typingTimersRef.current[userId]);
      }
      setTypingUsers(prev => prev.filter(u => u !== userName));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user?.id]);

  // ====================================
  // REALTIME SUBSCRIPTION (WITH SAFETY)
  // ====================================

  const setupRealtime = useCallback(() => {
    if (!teamId || !user || !profile || !authReady) return;

    // Clean up existing channel
    if (channelRef.current) {
      console.log('[TeamChat] Cleaning up existing channel');
      supabase.removeChannel(channelRef.current);
      channelRef.current = null;
    }

    console.log('[TeamChat] Setting up realtime for team:', teamId);

    try {
      const channel = supabase.channel(`team:${teamId}`, {
        config: {
          broadcast: { self: false },
          presence: { key: user.id },
        },
      });

      // Listen for new messages
      channel.on(
        'postgres_changes' as any,
        {
          event: 'INSERT',
          schema: 'public',
          table: 'team_messages',
          filter: `team_id=eq.${teamId}`,
        },
        async (payload: RealtimePayload<TeamMessage>) => {
          if (!isMounted.current) return;

          console.log('[TeamChat] New message received:', payload.new);

          const newMessage = payload.new;

          // Prevent duplicates
          setMessages((prev) => {
            const exists = prev.some((m) => m.id === newMessage.id);
            if (exists) return prev;

            // Remove optimistic if exists
            const filtered = prev.filter((m) => !m.isOptimistic);

            return [...filtered, { ...newMessage, isOwn: newMessage.sender_id === user.id }];
          });

          // Mark as read
          if (newMessage.sender_id !== user.id) {
            await markMessagesRead(teamId);
          }
        }
      );

      // Listen for message updates (like soft deletion)
      channel.on(
        'postgres_changes' as any,
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'team_messages',
          filter: `team_id=eq.${teamId}`,
        },
        async (payload: RealtimePayload<TeamMessage>) => {
          if (!isMounted.current) return;
          const updatedMsg = payload.new;
          if (updatedMsg.is_deleted) {
             setMessages(prev => prev.filter(m => m.id !== updatedMsg.id));
          } else if (updatedMsg.is_edited) {
             setMessages(prev => prev.map(m => m.id === updatedMsg.id ? { ...m, content: updatedMsg.content, is_edited: true, updated_at: updatedMsg.updated_at } : m));
          } else if (updatedMsg.content) {
             // Catch-all for other updates that change content
             setMessages(prev => prev.map(m => m.id === updatedMsg.id ? { ...m, content: updatedMsg.content, updated_at: updatedMsg.updated_at, is_edited: updatedMsg.is_edited } : m));
          }
        }
      );

      // Listen for member changes
      channel.on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'team_members',
          filter: `team_id=eq.${teamId}`,
        },
        async () => {
          if (!isMounted.current) return;
          console.log('[TeamChat] Member change detected, reloading members');
          const updatedMembers = await getTeamMembers(teamId);
          if (isMounted.current) {
            setMembers(updatedMembers);
          }
        }
      );

      // Subscribe with error handling
      channel
        .subscribe((status) => {
          console.log('[TeamChat] Subscription status:', status);

          if (status === 'SUBSCRIBED') {
            setConnected(true);
            retryCountRef.current = 0;
            toast.success('Connected to team chat', { duration: 2000, icon: '🟢' });
          } else if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
            setConnected(false);
            handleReconnect();
          } else if (status === 'CLOSED') {
            setConnected(false);
          }
        });

      // Listen for typing broadcast
      channel.on('broadcast', { event: 'user_typing' }, ({ payload }) => {
        handleTypingEvent(payload);
      });

      channelRef.current = channel;
    } catch (err) {
      console.error('[TeamChat] Failed to setup realtime:', err);
      setConnected(false);
      handleReconnect();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [teamId, user, profile, authReady]);

  // ====================================
  // RECONNECTION WITH EXPONENTIAL BACKOFF
  // ====================================

  const handleReconnect = useCallback(() => {
    if (retryCountRef.current >= BACKOFF_CONFIG.maxRetries) {
      console.warn('[TeamChat] Max retries reached, switching to polling');
      toast.error('Real-time connection lost. Refresh to reconnect.', { duration: 5000 });
      setConnected(false);
      return;
    }

    retryCountRef.current += 1;
    const delay = Math.min(
      BACKOFF_CONFIG.initialDelay * Math.pow(2, retryCountRef.current - 1),
      BACKOFF_CONFIG.maxDelay
    );

    console.log(
      `[TeamChat] Reconnecting in ${delay}ms (attempt ${retryCountRef.current}/${BACKOFF_CONFIG.maxRetries})`
    );

    if (retryTimeoutRef.current) {
      clearTimeout(retryTimeoutRef.current);
    }

    retryTimeoutRef.current = setTimeout(() => {
      if (isMounted.current) {
        setupRealtime();
      }
    }, delay);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [setupRealtime]);

  // ====================================
  // EFFECTS
  // ====================================

  // Load initial data on mount
  useEffect(() => {
    isMounted.current = true;
    loadInitialData();

    return () => {
      isMounted.current = false;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [loadInitialData]);

  // Setup realtime after initial load
  useEffect(() => {
    if (!loading && teamId && user && profile && authReady) {
      setupRealtime();
    }

    return () => {
      if (channelRef.current) {
        console.log('[TeamChat] Cleaning up channel on unmount');
        supabase.removeChannel(channelRef.current);
        channelRef.current = null;
      }
      if (retryTimeoutRef.current) {
        clearTimeout(retryTimeoutRef.current);
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [loading, teamId, user, setupRealtime]);

  // ====================================
  // CONTEXT VALUE
  // ====================================

  const value: TeamChatContextValue = {
    messages,
    members,
    loading,
    connected,
    sendMessage,
    shareNote,
    loadMoreMessages,
    hasMore,
    deleteMessage,
    editMessage,
    clearChatHistory,
    sendTypingStatus,
    typingUsers,
    teamStats,
    error,
  };

  return <TeamChatContext.Provider value={value}>{children}</TeamChatContext.Provider>;
};

import { useState, useEffect, useRef } from 'react';
import { getStoredAccounts } from '../utils/accountManager';
import { API_URL } from '../lib/api';
import { useAuth } from '../context/AuthContext';

export const useMultiAccountNotifications = () => {
  const { user } = useAuth();
  const [unreadCounts, setUnreadCounts] = useState<Record<string, number>>({});
  const accounts = getStoredAccounts();
  const intervalRef = useRef<any>(null);

  const fetchUnreadCounts = async () => {
    const updatedCounts: Record<string, number> = { ...unreadCounts };

    // Only poll for accounts that are NOT the current active user
    // (Active user's count is handled by NotificationContext)
    const otherAccounts = accounts.filter(acc => acc.id !== user?.id);

    for (const acc of otherAccounts) {
      try {
        const res = await fetch(`${API_URL}/api/notifications/unread-count`, {
          headers: {
            'Authorization': `Bearer ${acc.session.access_token}`
          }
        });

        if (res.ok) {
          const { count } = await res.json();
          updatedCounts[acc.id] = count;
        } else if (res.status === 401) {
          // Token expired? We could potentially refresh it here or just mark as error
          console.warn(`[MultiAccountAuth] Token expired for account ${acc.id}`);
        }
      } catch (err) {
        console.error(`[MultiAccountAuth] Failed to fetch count for ${acc.id}:`, err);
      }
    }

    setUnreadCounts(updatedCounts);
  };

  useEffect(() => {
    // Initial fetch
    fetchUnreadCounts();

    // Poll every 60 seconds
    intervalRef.current = setInterval(fetchUnreadCounts, 60000);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [user?.id, accounts.length]);

  return { unreadCounts };
};

import React, { useState, useEffect, useRef } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useWallet } from '../hooks/useWallet';
import { useSocket } from '../context/SocketContext';
import walletApi from '../api/walletApi';
import { WalletBalanceCard } from '../components/WalletBalance';
import { ActionsGrid } from '../components/wallet/ActionsGrid';
import { CurrencyList } from '../components/wallet/CurrencyList';
import { SwapCard } from '../components/SwapCard';
import { TransactionHistory } from '../components/TransactionList';
import { FundModal } from '../components/wallet/FundModal';
import { TransferModal } from '../components/wallet/TransferModal';
import { WithdrawModal } from '../components/wallet/WithdrawModal';
import { ReceiveModal } from '../components/wallet/ReceiveModal';
import { WalletAllocationChart } from '../components/wallet/WalletAllocationChart';
import { LedgerTrail } from '../components/wallet/LedgerTrail';
import { RefreshCw, Plus, X, Loader2 } from 'lucide-react';
import { Button } from '../components/common/Button';
import { formatCurrency } from '../lib/CurrencyFormatter';
import toast from 'react-hot-toast';

const SUPPORTED_CURRENCIES = ['BTC', 'ETH', 'USD', 'NGN', 'EUR', 'GBP', 'JPY'];

export const WalletPage: React.FC = () => {
    const { wallets, transactions, loading, refresh, createWallet } = useWallet();
    const { socket } = useSocket();
    
    // Force-refresh service data on mount (ensures fresh data after activity redirect)
    useEffect(() => {
        refresh();
    }, []); // eslint-disable-line react-hooks/exhaustive-deps
    
    const safeTransactions = Array.isArray(transactions) ? transactions : [];
    
    const [rates, setRates] = useState<Record<string, number>>({}); // Rates in USD
    const [totalBalance, setTotalBalance] = useState(0);
    const [totalAvailableBalance, setTotalAvailableBalance] = useState(0);
    const [ratesLoading, setRatesLoading] = useState(true);
    const [refreshKey, setRefreshKey] = useState(0);
    const [showBalances, setShowBalances] = useState(true);
    const [searchParams, setSearchParams] = useSearchParams();

    // Instant Proactive Polling for external redirects (e.g. Flutterwave/Paystack)
    useEffect(() => {
        const txRef = searchParams.get('tx_ref');
        const reference = searchParams.get('reference');
        const transactionId = searchParams.get('transaction_id') || searchParams.get('flw_ref');
        const statusParam = searchParams.get('status');

        const refToVerify = txRef || reference;

        if (refToVerify && (statusParam || reference)) {
            let isActive = true;
            const verifyPayment = async () => {
                const toastId = toast.loading('Verifying your request...', { duration: 10000 });
                try {
                    const res = await walletApi.proactiveVerifyPayment(refToVerify, transactionId || undefined);
                    if (!isActive) return;

                    const upperStatus = (res.status || '').toUpperCase();
                    if (['COMPLETED', 'SUCCESS', 'SUCCESSFUL'].includes(upperStatus)) {
                        toast.success('Request processed successfully!', { id: toastId });
                        setSearchParams({});
                        await refresh();
                        setRefreshKey(k => k + 1);
                    } else if (['FAILED', 'CANCELLED'].includes(upperStatus)) {
                        toast.error('Request failed or was cancelled.', { id: toastId });
                        setSearchParams({});
                    } else {
                        toast.success('Request is pending. Tracking your activity...', { id: toastId });
                        setSearchParams({});
                        await refresh();
                    }
                } catch (err) {
                    if (isActive) {
                        toast.error('Confirmation delayed. Status will update shortly.', { id: toastId });
                        setSearchParams({});
                    }
                }
            };
            verifyPayment();
            
            return () => { isActive = false; };
        }
    }, [searchParams, setSearchParams, refresh]);

    // Modals
    const [showFundModal, setShowFundModal] = useState(false);
    const [isBuyMode, setIsBuyMode] = useState(false);
    const [showTransferModal, setShowTransferModal] = useState(false);
    const [showWithdrawModal, setShowWithdrawModal] = useState(false);
    const [showReceiveModal, setShowReceiveModal] = useState(false);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [selectedAsset, setSelectedAsset] = useState<{ currency: string; network: string }>({ currency: 'BTC', network: 'native' });

    // Stats
    const swapCardRef = useRef<HTMLDivElement>(null);

    // Fetch Rates & Calculate Total
    useEffect(() => {
        const processExchangeRates = (exchangeRates: Record<string, any>) => {
            const usdRates: Record<string, number> = {};
            
            Object.keys(exchangeRates).forEach(curr => {
                let val = exchangeRates[curr];
                
                // Handle objects (old provider format)
                if (typeof val === 'object' && val !== null) {
                    val = val['USD'] || val[curr] || 0;
                }

                const numVal = typeof val === 'string' ? parseFloat(val) : val;
                
                if (typeof numVal === 'number' && !isNaN(numVal) && numVal > 0) {
                    // Convert "1 USD = X Currency" to "1 Currency = Y USD"
                    usdRates[curr] = 1 / numVal;
                }
            });

            usdRates['USD'] = 1;
            setRates(usdRates);
            setRatesLoading(false);
        };

        const fetchRates = async () => {
            setRatesLoading(true);
            try {
                const exchangeRates = await walletApi.getExchangeRates();
                processExchangeRates(exchangeRates);
            } catch (err) {
                console.error('Failed to fetch rates', err);
                setRatesLoading(false);
            }
        };

        // Initial fetch
        if (Array.isArray(wallets) && wallets.length > 0) {
            fetchRates();
        }

        // Socket.io Listener: Active Real-time Overwrite
        if (socket) {
            socket.on('rates_updated', (newRates: any) => {
                console.log('[Socket] Rates updated in real-time');
                processExchangeRates(newRates);
            });

            return () => {
                socket.off('rates_updated');
            };
        }
    }, [wallets.length, socket]);

    // Calculate Total Balance & Available Balance
    useEffect(() => {
        if (wallets.length > 0 && Object.keys(rates).length > 0) {
            let total = 0;
            let available = 0;
            const safeWallets = Array.isArray(wallets) ? wallets : [];
            
            safeWallets.forEach(w => {
                const rate = rates[w.currency] || 0;
                // Using a slightly more robust multiplication to reduce float noise
                const balValue = Number((w.balance * rate).toFixed(12));
                const availValue = Number(((w.available_balance ?? w.balance) * rate).toFixed(12));
                
                total += balValue;
                available += availValue;
            });

            setTotalBalance(Number(total.toFixed(8)));
            setTotalAvailableBalance(Number(available.toFixed(8)));
        }
    }, [wallets, rates]);

    const handleAction = (action: 'send' | 'receive' | 'fund' | 'withdraw' | 'swap' | 'buy') => {
        const safeWallets = Array.isArray(wallets) ? wallets : [];
        if (!selectedAsset.currency && safeWallets.length > 0) {
            // Prefer a fiat wallet as default for global actions (better feature discoverability)
            const fiatWallet = safeWallets.find(w => ['USD', 'EUR', 'NGN', 'GBP'].includes(w.currency));
            const defaultWallet = fiatWallet || safeWallets[0];
            setSelectedAsset({ currency: defaultWallet.currency, network: defaultWallet.network });
        }

        switch (action) {
            case 'fund':
                setShowFundModal(true);
                break;
            case 'buy':
                // For buy action, default to a crypto wallet to trigger direct purchase
                if (['USD', 'EUR', 'NGN', 'GBP'].includes(selectedAsset.currency)) {
                    const cryptoWallet = safeWallets.find(w => !['USD', 'EUR', 'NGN', 'GBP'].includes(w.currency));
                    if (cryptoWallet) {
                        setSelectedAsset({ currency: cryptoWallet.currency, network: cryptoWallet.network });
                    }
                }
                setIsBuyMode(true);
                setShowFundModal(true);
                break;
            case 'send':
                setShowTransferModal(true);
                break;
            case 'withdraw':
                setShowWithdrawModal(true);
                break;
            case 'swap':
                swapCardRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
                break;
            case 'receive':
                setShowReceiveModal(true);
                break;
        }
    };

    const handleCreateWallet = async (currency: string) => {
        try {
            await createWallet(currency);
            toast.success(`${currency} service activated!`);
            setShowCreateModal(false);
            refresh();
        } catch (err) {
           // handled in context
        }
    };

    const handleRefresh = () => {
        refresh();
        setRefreshKey(k => k + 1); // Trigger ledger trail refresh
    };

    return (
        <div className="min-h-[100dvh] bg-gray-950 text-white p-4 sm:p-6 lg:p-8 overflow-x-clip w-full">
            <div className="max-w-7xl mx-auto space-y-8">
                
                {/* Market Price Ticker */}
                {!loading && Object.keys(rates).length > 0 && (
                    <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-none no-scrollbar">
                        {['BTC', 'ETH'].map(curr => (
                            <div key={curr} className="flex items-center gap-2 bg-white/5 border border-white/10 px-3 py-1.5 rounded-full shrink-0">
                                <span className={`w-2 h-2 rounded-full bg-green-400 animate-pulse`} />
                                <span className="text-xs font-bold text-gray-300">{curr}/USD</span>
                                <span className="text-xs font-black text-white">
                                    { (rates[curr] || 0) < 0.01 
                                        ? `$${(rates[curr] || 0).toFixed((rates[curr] || 0) < 0.0001 ? 6 : 4)}` 
                                        : formatCurrency(rates[curr] || 0, 'USD') 
                                    }
                                </span>
                            </div>
                        ))}
                    </div>
                )}

                {/* Header */}
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-2xl sm:text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-gray-400">
                            Activity Overview
                        </h1>
                        <p className="text-gray-400 text-sm mt-1">Manage your digital activities and technology tools</p>
                    </div>
                    <div className="flex gap-3">
                         <Button onClick={() => setShowCreateModal(true)} variant="outline" size="sm" className="hidden sm:flex border-gray-700 hover:border-purple-500">
                            <Plus size={16} className="mr-2" /> Add Service
                        </Button>
                        <Button onClick={handleRefresh} variant="ghost" size="sm" className="bg-gray-800 hover:bg-gray-700">
                            <RefreshCw size={18} className={loading ? 'animate-spin' : ''} />
                        </Button>
                    </div>
                </div>

                {/* Top Section: Balance & Actions */}
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* Left: Balance Card */}
                    <div className="lg:col-span-2 space-y-6">
                        <WalletBalanceCard 
                            totalBalance={totalBalance} 
                            availableBalance={totalAvailableBalance}
                            currency="USD"
                            loading={ratesLoading || loading}
                            showBalance={showBalances}
                            onToggleBalance={() => setShowBalances(!showBalances)}
                        />

                        {/* Quick Actions */}
                        <ActionsGrid 
                            onSend={() => handleAction('send')}
                            onReceive={() => handleAction('receive')}
                            onSwap={() => handleAction('swap')}
                            onWithdraw={() => handleAction('withdraw')}
                            onDeposit={() => handleAction('fund')}
                            onBuy={() => handleAction('buy')}
                            disabledActions={
                                ['BTC', 'ETH', 'USDT', 'USDC'].some(c => selectedAsset.currency?.startsWith(c)) 
                                ? ['Move In'] 
                                : []
                            }
                        />
                         
                         {/* Wallet List (Breakdown) */}
                         <div>
                            <div className="flex justify-between items-center gap-4 mb-4 flex-wrap">
                                <h3 className="text-lg font-bold">Your Services</h3>
                                <button onClick={() => setShowCreateModal(true)} className="text-purple-400 text-sm hover:text-purple-300 sm:hidden">
                                    + Add New
                                </button>
                            </div>
                            {loading ? (
                                <div className="text-center py-10">
                                    <Loader2 className="animate-spin text-purple-500 mx-auto" size={32} />
                                </div>
                            ) : (
                                <CurrencyList 
                                    wallets={wallets} 
                                    rates={rates} 
                                    onSelect={(curr, net) => setSelectedAsset({ currency: curr, network: net || 'native' })}
                                    showBalances={showBalances}
                                />
                            )}
                        </div>
                    </div>

                    {/* Right: Swap Module + Allocation Chart + Ledger Trail */}
                    <div className="lg:col-span-1">
                        <div className="sticky top-6 space-y-6">
                           <div ref={swapCardRef}>
                                <SwapCard 
                                    initialFromCurrency={selectedAsset.currency} 
                                    initialFromNetwork={selectedAsset.network}
                                    onSuccess={() => {
                                        handleRefresh();
                                        toast.success('Balance updated');
                                    }}
                                />
                           </div>
                           
                           {/* Allocation Chart */}
                           <WalletAllocationChart wallets={wallets} rates={rates} />

                           {/* Ledger Audit Trail */}
                           <LedgerTrail refreshKey={refreshKey} />
                        </div>
                    </div>
                </div>

                {/* Bottom Section: Transaction History */}
                <div className="pb-12">
                     <TransactionHistory 
                        transactions={safeTransactions} 
                        loading={loading}
                     />
                </div>

            </div>

            {/* Modals */}
            {showFundModal && (
                <FundModal 
                    isOpen={showFundModal} 
                    onClose={() => {
                        setShowFundModal(false);
                        setIsBuyMode(false);
                    }} 
                    selectedCurrency={selectedAsset.currency}
                    selectedNetwork={selectedAsset.network}
                    onSuccess={handleRefresh}
                    initialIsPurchase={isBuyMode}
                />
            )}
            {showTransferModal && (
                <TransferModal
                    isOpen={showTransferModal}
                    onClose={() => setShowTransferModal(false)}
                    selectedCurrency={selectedAsset.currency}
                    selectedNetwork={selectedAsset.network}
                    onSuccess={() => {
                        handleRefresh();
                    }}
                />
            )}
            {showWithdrawModal && (
                <WithdrawModal
                    isOpen={showWithdrawModal}
                    onClose={() => setShowWithdrawModal(false)}
                    selectedCurrency={selectedAsset.currency}
                    selectedNetwork={selectedAsset.network}
                    onSuccess={() => {
                        handleRefresh();
                        toast.success('Withdrawal initiated');
                    }}
                />
            )}
            {showReceiveModal && (
                <ReceiveModal
                    isOpen={showReceiveModal}
                    onClose={() => setShowReceiveModal(false)}
                    initialCurrency={selectedAsset.currency}
                    initialNetwork={selectedAsset.network}
                />
            )}

            {/* Create Service Modal */}
             {showCreateModal && (
                <div className="modal-overlay p-4">
                  <div className="modal-content w-full max-w-lg">

                    <button className="modal-close" onClick={() => setShowCreateModal(false)}>
                      <X size={20} />
                    </button>
                    <h2 className="text-xl font-bold mb-6">Add New Service</h2>
                    
                    <div className="grid grid-cols-2 gap-4">
                      {(SUPPORTED_CURRENCIES ?? []).map((curr) => {
                        const exists = (wallets ?? []).some(w => w.currency === curr);
                        if (exists) return null;
                        
                        return (
                          <button
                            key={curr}
                            onClick={() => handleCreateWallet(curr)}
                            className="p-4 border border-gray-700 rounded-xl hover:border-purple-500 hover:bg-gray-800 transition-all flex flex-col items-center gap-2 group"
                          >
                            <span className="text-2xl group-hover:scale-110 transition-transform">{curr === 'BTC' ? '₿' : curr === 'ETH' ? 'Ξ' : '$'}</span>
                            <span className="font-bold text-gray-300 group-hover:text-white">{curr}</span>
                          </button>
                        );
                      })}
                      {wallets.length === SUPPORTED_CURRENCIES.length && (
                          <p className="col-span-2 text-center text-gray-500 py-4">All available services active.</p>
                      )}
                    </div>
                  </div>
                </div>
              )}
        </div>
    );
};

import { useState, useEffect } from 'react';
import {
    Settings,
    Shield,
    Bot,
    Server,
    Database,
    Lock,
    Save,
    Loader2,
    ExternalLink
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { API_URL } from '../../lib/api';
import { toast } from 'react-hot-toast';
import './AdminSettings.css';

interface SystemSettings {
    system_name: string;
    maintenance_mode: boolean;
    registration_status: string;
    admin_2fa_enabled: boolean;
}

export const AdminSettings = () => {
    const { session } = useAuth();
    const [settings, setSettings] = useState<SystemSettings>({
        system_name: 'Note Standard Admin',
        maintenance_mode: false,
        registration_status: 'public',
        admin_2fa_enabled: true
    });
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        fetchSettings();
    }, [session]);

    const fetchSettings = async () => {
        if (!session?.access_token) return;
        setLoading(true);
        try {
            const res = await fetch(`${API_URL}/api/admin/settings`, {
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                }
            });
            if (res.ok) {
                const data = await res.json();
                setSettings({
                    system_name: data.system_name,
                    maintenance_mode: data.maintenance_mode,
                    registration_status: data.registration_status,
                    admin_2fa_enabled: data.admin_2fa_enabled
                });
            }
        } catch (err) {
            console.error('Failed to fetch settings:', err);
            toast.error('Failed to load system settings');
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async () => {
        if (!session?.access_token) return;
        setSaving(true);
        try {
            const res = await fetch(`${API_URL}/api/admin/settings`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify(settings)
            });

            if (res.ok) {
                toast.success('System settings updated');
            } else {
                throw new Error('Failed to update');
            }
        } catch (err) {
            console.error(err);
            toast.error('Failed to save settings');
        } finally {
            setSaving(false);
        }
    };

    if (loading) {
        return <div className="flex justify-center py-20"><Loader2 className="animate-spin text-primary" size={32} /></div>;
    }

    return (
        <div className="admin-settings-page">
            <div className="settings-header">
                <div className="header-title">
                    <Settings className="header-icon" />
                    <div className="header-info">
                        <h2>System Settings</h2>
                        <p>Global configuration and security controls</p>
                    </div>
                </div>
                <button
                    className={`save-btn ${saving ? 'saving' : ''}`}
                    onClick={handleSave}
                    disabled={saving}
                >
                    {saving ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                    {saving ? 'Saving...' : 'Save Changes'}
                </button>
            </div>

            <div className="settings-container">
                {/* General Settings */}
                <section className="settings-section">
                    <div className="section-header">
                        <Settings size={20} />
                        <h3>General Configuration</h3>
                    </div>
                    <div className="section-content">
                        <div className="input-group">
                            <label htmlFor="systemName">System Name</label>
                            <input 
                                id="systemName" 
                                name="systemName"
                                type="text" 
                                value={settings.system_name} 
                                onChange={(e) => setSettings(prev => ({ ...prev, system_name: e.target.value }))}
                                autoComplete="organization"
                            />
                        </div>
                        <div className="input-group">
                            <label htmlFor="maintenance">Maintenance Mode</label>
                            <div className="toggle-switch">
                                <input 
                                    type="checkbox" 
                                    id="maintenance" 
                                    name="maintenance"
                                    checked={settings.maintenance_mode}
                                    onChange={(e) => setSettings(prev => ({ ...prev, maintenance_mode: e.target.checked }))}
                                    autoComplete="off"
                                />
                                <label htmlFor="maintenance"></label>
                                <span className="toggle-status">{settings.maintenance_mode ? 'Enabled' : 'Disabled'}</span>
                            </div>
                        </div>
                    </div>
                </section>

                {/* Security Settings */}
                <section className="settings-section">
                    <div className="section-header">
                        <Shield size={20} />
                        <h3>Security & Access</h3>
                    </div>
                    <div className="section-content">
                        <div className="input-group">
                            <label htmlFor="regStatus">Registration Status</label>
                            <select 
                                id="regStatus" 
                                name="regStatus"
                                value={settings.registration_status}
                                onChange={(e) => setSettings(prev => ({ ...prev, registration_status: e.target.value }))}
                            >
                                <option value="public">Public (Anyone can join)</option>
                                <option value="invite">Invite Only</option>
                                <option value="closed">Closed</option>
                            </select>
                        </div>
                        <div className="input-group">
                            <span id="label-2fa" className="text-sm font-medium text-gray-400 mb-1 block">Admin 2FA</span>
                            <div className={`status-badge ${settings.admin_2fa_enabled ? 'secure' : 'warning'}`}>
                                {settings.admin_2fa_enabled ? 'Enabled' : 'Disabled'}
                            </div>
                            <button 
                                type="button"
                                aria-labelledby="label-2fa"
                                className="text-xs text-primary hover:underline mt-1 bg-transparent border-none p-0"
                                onClick={() => setSettings(prev => ({ ...prev, admin_2fa_enabled: !prev.admin_2fa_enabled }))}
                            >
                                Toggle 2FA Requirement
                            </button>
                        </div>
                    </div>
                </section>

                {/* Quick Shortcuts */}
                <div className="shortcuts-grid">
                    <a href="/admin/auto-reply" className="shortcut-card">
                        <div className="shortcut-icon bot">
                            <Bot size={24} />
                        </div>
                        <div className="shortcut-info">
                            <h4>Auto-Reply Config</h4>
                            <p>Manage support bot behavior</p>
                        </div>
                        <ExternalLink size={16} className="arrow" />
                    </a>

                    <div className="shortcut-card disabled">
                        <div className="shortcut-icon backup">
                            <Database size={24} />
                        </div>
                        <div className="shortcut-info">
                            <h4>Database Backups</h4>
                            <p>Configure automated backups</p>
                        </div>
                        <Lock size={16} className="lock" />
                    </div>
                </div>

                {/* Infrastructure Info */}
                <section className="settings-section info">
                    <div className="section-header">
                        <Server size={20} />
                        <h3>Infrastructure</h3>
                    </div>
                    <div className="info-grid">
                        <div className="info-item">
                            <span>API Version</span>
                            <strong>v1.4.2-stable</strong>
                        </div>
                        <div className="info-item">
                            <span>Environment</span>
                            <strong>Production</strong>
                        </div>
                        <div className="info-item">
                            <span>Region</span>
                            <strong>us-east-1</strong>
                        </div>
                        <div className="info-item">
                            <span>Uptime</span>
                            <strong>99.98%</strong>
                        </div>
                    </div>
                </section>
            </div>
        </div>
    );
};

import { useState, useEffect, useMemo } from 'react';
import { useAuth } from '../../context/AuthContext';
import { toast } from 'react-hot-toast';
import {
    Users,
    Activity as ActivityIcon,
    FileText,
    MessageSquare,
    Calendar,
    ArrowUpRight,
    Loader2
} from 'lucide-react';
import { API_URL } from '../../lib/api';
import './Analytics.css';

interface DetailedStats {
    totalUsers: number;
    activeUsers: number;
    totalNotes: number;
    openChats: number;
    onlineUsers: number;
    growthRate?: string;
    noteGrowth?: string;
    chatRetention?: string;
    usageTrends?: { day: string; notes: number; users: number }[];
    topCreators?: { id: string; name: string; count: number }[];
    systemLoad?: { cpu: number; memory: number };
}

export const Analytics = () => {
    const { session } = useAuth();
    const [stats, setStats] = useState<DetailedStats | null>(null);
    const [loading, setLoading] = useState(true);
    const [timeframe, setTimeframe] = useState('7d');

    useEffect(() => {
        fetchDetailedStats();
    }, [session, timeframe]);

    const fetchDetailedStats = async () => {
        if (!session?.access_token) return;
        setLoading(true);
        try {
            const res = await fetch(`${API_URL}/api/admin/analytics/detailed`, {
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                }
            });
            const data = await res.json();

            // Use real data from API (no mocks)
            setStats(data);
        } catch (err) {
            console.error('Failed to fetch analytics:', err);
            toast.error('Failed to load real-time analytics');
        } finally {
            setLoading(false);
        }
    };

    // Calc max for chart scaling
    const maxTrendValue = useMemo(() => {
        return stats?.usageTrends
            ? Math.max(...stats.usageTrends.map(d => Math.max(d.notes, d.users)), 10)
            : 10;
    }, [stats?.usageTrends]);

    if (loading) {
        return (
            <div className="analytics-page loading">
                <Loader2 className="spinner" />
                <p>Calculating insights...</p>
            </div>
        );
    }

    return (
        <div className="analytics-page">
            <div className="analytics-header">
                <div className="header-title">
                    <ActivityIcon className="header-icon" />
                    <div className="header-info">
                        <h2>Advanced Analytics</h2>
                        <p>Real-time system usage and growth metrics</p>
                    </div>
                </div>
                <div className="timeframe-selector">
                    <Calendar size={18} />
                    <select 
                        id="analytics-timeframe" 
                        name="timeframe"
                        value={timeframe} 
                        onChange={(e) => setTimeframe(e.target.value)}
                    >
                        <option value="7d">Last 7 Days</option>
                        {/* Future: Add backend support for other ranges */}
                    </select>
                </div>
            </div>

            <div className="analytics-grid">
                {/* Main KPIs */}
                <div className="analytics-card kpi">
                    <div className="kpi-icon users">
                        <Users size={24} />
                    </div>
                    <div className="kpi-data">
                        <span className="kpi-label">User Growth</span>
                        <h3 className="kpi-value">{stats?.totalUsers}</h3>
                        <span className="trend positive">
                            <ArrowUpRight size={16} />
                            {stats?.growthRate || '0%'}
                        </span>
                    </div>
                </div>

                <div className="analytics-card kpi">
                    <div className="kpi-icon activity">
                        <ActivityIcon size={24} />
                    </div>
                    <div className="kpi-data">
                        <span className="kpi-label">Active Engagement</span>
                        <h3 className="kpi-value">{stats?.activeUsers}</h3>
                        <span className="trend positive">
                            {/* Just an activity metric for now */}
                            Live
                        </span>
                    </div>
                </div>

                <div className="analytics-card kpi">
                    <div className="kpi-icon notes">
                        <FileText size={24} />
                    </div>
                    <div className="kpi-data">
                        <span className="kpi-label">Content Created</span>
                        <h3 className="kpi-value">{stats?.totalNotes}</h3>
                        <span className="trend positive">
                            <ArrowUpRight size={16} />
                            {stats?.noteGrowth || '0%'}
                        </span>
                    </div>
                </div>

                <div className="analytics-card kpi">
                    <div className="kpi-icon chats">
                        <MessageSquare size={24} />
                    </div>
                    <div className="kpi-data">
                        <span className="kpi-label">Resolution Rate</span>
                        <h3 className="kpi-value">{stats?.chatRetention || '0%'}</h3>
                        <span className="trend neutral">
                            Efficiency
                        </span>
                    </div>
                </div>
            </div>

            <div className="detailed-analytics">
                <div className="analytics-chart-placeholder" style={{ display: 'flex', flexDirection: 'column' }}>
                    <div className="chart-header">
                        <h4>Usage Trends</h4>
                        <div className="chart-legend">
                            <span className="legend-item"><span className="dot users" /> Users</span>
                            <span className="legend-item"><span className="dot notes" /> Notes</span>
                        </div>
                    </div>

                    <div className="flex-1 flex items-end justify-between gap-4 h-64 px-2 pb-2">
                        {stats?.usageTrends?.map((trend) => (
                            <div key={trend.day} className="flex flex-col items-center gap-2 w-full h-full justify-end group relative">
                                <div className="w-full flex gap-1 items-end justify-center h-full">
                                    {/* Users Bar */}
                                    <div
                                        className="w-3 md:w-6 bg-blue-500/50 rounded-t-sm hover:bg-blue-500 transition-all relative"
                                        style={{ height: `${(trend.users / maxTrendValue) * 100}%` }}
                                        title={`${trend.users} users`}
                                    />
                                    {/* Notes Bar */}
                                    <div
                                        className="w-3 md:w-6 bg-purple-500/50 rounded-t-sm hover:bg-purple-500 transition-all relative"
                                        style={{ height: `${(trend.notes / maxTrendValue) * 100}%` }}
                                        title={`${trend.notes} notes`}
                                    />
                                </div>
                                <span className="text-xs text-gray-400 font-medium">{trend.day}</span>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="secondary-stats">
                    <div className="analytics-card mini">
                        <h4>Top Creators</h4>
                        <div className="mini-list">
                            {stats?.topCreators?.length ? (
                                stats?.topCreators?.map((creator, i) => (
                                    <div key={creator.id} className="mini-item">
                                        <span>#{i + 1} {creator.name}</span>
                                        <strong>{creator.count} notes</strong>
                                    </div>
                                ))
