                                <p className="text-sm text-gray-500 p-2">No creators data</p>
                            )}
                        </div>
                    </div>

                    <div className="analytics-card mini">
                        <h4>System Load</h4>
                        <div className="space-y-4 pt-2">
                            <div>
                                <div className="flex justify-between text-xs mb-1">
