                                <div className="load-meter">
                                    <div
                                        className="meter-fill"
                                        style={{ width: `${stats?.systemLoad?.cpu || 0}%` }}
                                    />
                                </div>
                            </div>
                            <div>
                                <div className="flex justify-between text-xs mb-1">
                                    <span>Memory</span>
                                    <span>{stats?.systemLoad?.memory || 0}%</span>
                                </div>
                                <div className="load-meter">
                                    <div
                                        className="meter-fill"
                                        style={{ width: `${stats?.systemLoad?.memory || 0}%`, background: '#a855f7' }}
                                    />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

import { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { toast } from 'react-hot-toast';
import {
    History as HistoryIcon,
    Filter,
    Activity as ActivityIcon,
    ChevronLeft,
    ChevronRight
} from 'lucide-react';
import { API_URL } from '../../lib/api';
import SecureImage from '../../components/common/SecureImage';
import './AuditLogs.css';

interface AuditLog {
    id: string;
    admin_id: string;
    action: string;
    target_type: string;
    target_id: string;
    details: any;
    ip_address: string;
    created_at: string;
    admin: {
        username: string;
        full_name: string;
        avatar_url: string;
    };
}

interface Pagination {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
}

export const AuditLogs = () => {
    const { session } = useAuth();
    const [logs, setLogs] = useState<AuditLog[]>([]);
    const [pagination, setPagination] = useState<Pagination>({
        page: 1,
        limit: 20,
        total: 0,
        totalPages: 0
    });
    const [loading, setLoading] = useState(true);
    const [actionFilter, setActionFilter] = useState('');
    const [targetFilter, setTargetFilter] = useState('');

    useEffect(() => {
        fetchLogs();
    }, [session, pagination.page, actionFilter, targetFilter]);

    const fetchLogs = async () => {
        if (!session?.access_token) return;
        setLoading(true);

        try {
            const params = new URLSearchParams({
                page: pagination.page.toString(),
                limit: pagination.limit.toString(),
                ...(actionFilter && { action: actionFilter }),
                ...(targetFilter && { target_type: targetFilter })
            });

            const res = await fetch(`${API_URL}/api/admin/audit-logs?${params}`, {
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                }
            });

            if (!res.ok) throw new Error('Failed to fetch audit logs');

            const data = await res.json() || {};
            setLogs(data.logs || []);
            setPagination(data.pagination || {
                page: 1,
                limit: 20,
                total: 0,
                totalPages: 0
            });
        } catch (err) {
            console.error('Failed to fetch audit logs:', err);
            toast.error('Failed to load audit logs');
        } finally {
            setLoading(false);
        }
    };

    const formatDate = (dateStr: string) => {
        const date = new Date(dateStr);
        return {
            date: date.toLocaleDateString(),
            time: date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        };
    };

    const getActionBadgeClass = (action: string) => {
        if (action.includes('suspend')) return 'danger';
        if (action.includes('update')) return 'warning';
        if (action.includes('broadcast')) return 'info';
        if (action.includes('join') || action.includes('resolve')) return 'success';
        return 'default';
    };

    const formatActionName = (action: string) => {
        return action.split('_').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');
    };

    return (
        <div className="audit-logs">
            <div className="page-header">
                <div className="header-title">
                    <HistoryIcon className="header-icon" />
                    <div>
                        <h2>Admin Audit Logs</h2>
                        <p>Track all administrative actions and security events</p>
                    </div>
                </div>
                <div className="stats-mini">
                    <div className="stat-item">
                        <span className="label">Total Events</span>
                        <span className="value">{pagination.total}</span>
                    </div>
                </div>
            </div>

            <div className="filters-bar">
                <div className="filter-group">
                    <ActivityIcon size={18} />
                    <select
                        id="audit-action-filter"
                        name="actionFilter"
                        value={actionFilter}
                        onChange={(e) => {
                            setActionFilter(e.target.value);
                            setPagination(prev => ({ ...prev, page: 1 }));
                        }}
                    >
                        <option value="">All Actions</option>
                        <option value="update_user_status">User Status Updates</option>
                        <option value="update_support_status">Support Status Updates</option>
                        <option value="join_support_chat">Admin Joins</option>
                        <option value="broadcast">Broadcast Messages</option>
                    </select>
                </div>

                <div className="filter-group">
                    <Filter size={18} />
                    <select
                        id="audit-target-filter"
                        name="targetFilter"
                        value={targetFilter}
                        onChange={(e) => {
                            setTargetFilter(e.target.value);
                            setPagination(prev => ({ ...prev, page: 1 }));
                        }}
                    >
                        <option value="">All Targets</option>
                        <option value="user">Users</option>
                        <option value="conversation">Conversations</option>
                        <option value="broadcast">Broadcasts</option>
                    </select>
                </div>
            </div>

            <div className="logs-table-container">
                <table className="logs-table">
                    <thead>
                        <tr>
                            <th>Time</th>
                            <th>Admin</th>
                            <th>Action</th>
                            <th>Target</th>
                            <th>IP Address</th>
                            <th>Details</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            Array(5).fill(0).map((_, i) => (
                                <tr key={i} className="skeleton-row">
                                    <td colSpan={6}><div className="skeleton-line" /></td>
                                </tr>
                            ))
                        ) : logs.length === 0 ? (
                            <tr>
                                <td colSpan={6} className="empty-row">No audit logs found</td>
                            </tr>
                        ) : (
                            logs?.map(log => {
                                const { date, time } = formatDate(log.created_at);
                                return (
                                    <tr key={log.id}>
                                        <td className="time-cell">
                                            <div className="date">{date}</div>
                                            <div className="time">{time}</div>
                                        </td>
                                        <td className="admin-cell">
                                            <div className="admin-info">
                                                {log.admin?.avatar_url ? (
                                                    <SecureImage src={log.admin.avatar_url} alt="" fallbackType="profile" />
                                                ) : (
                                                    <div className="avatar-placeholder">
                                                        {log.admin?.username?.[0]?.toUpperCase() || 'A'}
                                                    </div>
                                                )}
                                                <span>{log.admin?.username || 'Unknown Admin'}</span>
                                            </div>
                                        </td>
                                        <td>
                                            <span className={`action-badge ${getActionBadgeClass(log.action)}`}>
                                                {formatActionName(log.action)}
                                            </span>
                                        </td>
                                        <td className="target-cell">
                                            <span className="target-type">{log.target_type}</span>
                                            <span className="target-id">{log.target_id.slice(0, 8)}...</span>
                                        </td>
                                        <td className="ip-cell">{log.ip_address || 'Internal'}</td>
                                        <td className="details-cell">
                                            <pre>{JSON.stringify(log.details, null, 2)}</pre>
                                        </td>
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>

            {pagination.totalPages > 1 && (
                <div className="pagination">
                    <button
                        disabled={pagination.page === 1}
                        onClick={() => setPagination(prev => ({ ...prev, page: prev.page - 1 }))}
                    >
                        <ChevronLeft size={18} /> Previous
                    </button>
                    <span>Page {pagination.page} of {pagination.totalPages}</span>
                    <button
                        disabled={pagination.page === pagination.totalPages}
                        onClick={() => setPagination(prev => ({ ...prev, page: prev.page + 1 }))}
                    >
                        Next <ChevronRight size={18} />
                    </button>
                </div>
            )}
        </div>
    );
};

import { useState, useEffect } from 'react';
import { Bot, Save, Clock, Globe, ShieldAlert, Loader2 } from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { toast } from 'react-hot-toast';
import { API_URL } from '../../lib/api';
import './AutoReplySettings.css';

interface Settings {
    id?: string;
    enabled: boolean;
    message: string;
    start_hour: string;
    end_hour: string;
    timezone: string;
}

// Helper to ensure time is HH:mm format
const normalizeTime = (time: string | number | undefined | null) => {
    if (time === undefined || time === null || time === '') return '00:00';
    
    // Convert numbers to string safe
    const timeStr = time.toString();

    // Handle "9" or "18" -> "09:00", "18:00"
    if (!timeStr.includes(':')) {
        return `${timeStr.padStart(2, '0')}:00`;
    }
    // Handle "9:30" -> "09:30"
    const [h, m] = timeStr.split(':');
    return `${h.padStart(2, '0')}:${(m || '00').padStart(2, '0')}`;
};

export const AutoReplySettings = () => {
    const { session } = useAuth();
    const [settings, setSettings] = useState<Settings>({
        enabled: false,
        message: '',
        start_hour: '18:00',
        end_hour: '09:00',
        timezone: 'UTC'
    });
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [status, setStatus] = useState<{ type: 'success' | 'error', msg: string } | null>(null);

    useEffect(() => {
        fetchSettings();
    }, [session]);

    const fetchSettings = async () => {
        if (!session?.access_token) return;
        setLoading(true);
        try {
            const res = await fetch(`${API_URL}/api/admin/auto-reply`, {
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                }
            });
            if (res.ok) {
                const data = await res.json();
                setSettings({
                    ...data,
                    start_hour: normalizeTime(data.start_hour),
                    end_hour: normalizeTime(data.end_hour)
                });
            }
        } catch (err) {
            console.error('Failed to fetch settings:', err);
            toast.error('Failed to load auto-reply settings');
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!session?.access_token) return;
        setSaving(true);
        setStatus(null);

        try {
            const res = await fetch(`${API_URL}/api/admin/auto-reply`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                },
                body: JSON.stringify(settings)
            });

            if (res.ok) {
                const data = await res.json();
                setSettings(data);
                setStatus({ type: 'success', msg: 'Settings updated successfully' });
                toast.success('Settings saved');
            } else {
                throw new Error('Failed to update');
            }
        } catch (err) {
            setStatus({ type: 'error', msg: 'Failed to save settings' });
            toast.error('Failed to save settings');
        } finally {
            setSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="loading-state">
                <Loader2 size={32} className="animate-spin text-primary" />
            </div>
        );
    }

    return (
        <div className="autoreply-settings">
            <div className="page-header">
                <div className="header-title">
                    <Bot className="header-icon" />
                    <div>
                        <h2>AI Auto-Reply Settings</h2>
                        <p>Configure automated responses for offline hours</p>
                    </div>
                </div>
            </div>

            <form onSubmit={handleSave} className="settings-form">
                <div className="settings-section">
                    <div className="section-header">
                        <ShieldAlert size={20} />
                        <h3>Status & Message</h3>
                    </div>

                    <div className="form-group toggle">
                        <label className="toggle-label" htmlFor="enableAutoReply">
                            <span>Enable Auto-Reply</span>
                            <div className={`switch ${settings.enabled ? 'on' : ''}`}>
                                <input 
                                    type="checkbox" 
                                    id="enableAutoReply" 
                                    name="enabled"
                                    checked={settings.enabled}
                                    onChange={(e) => setSettings(prev => ({ ...prev, enabled: e.target.checked }))}
                                    style={{ opacity: 0, position: 'absolute', width: '100%', height: '100%', cursor: 'pointer', zIndex: 10, margin: 0, left: 0, top: 0 }}
                                />
                                <div className="slider" />
                            </div>
                        </label>
                    </div>

                    <div className="form-group">
                        <label htmlFor="offlineMessage">Offline Message</label>
                        <textarea
                            id="offlineMessage"
                            name="offlineMessage"
                            value={settings.message}
                            onChange={(e) => setSettings(prev => ({ ...prev, message: e.target.value }))}
                            placeholder="Thank you for contacting us. We are currently offline..."
                            rows={4}
                            required
                        />
                        <p className="hint">This message will be sent automatically to users who contact support during offline hours.</p>
                    </div>
                </div>

                <div className="settings-section">
                    <div className="section-header">
                        <Clock size={20} />
                        <h3>Offline Schedule</h3>
                    </div>

                    <div className="time-grid">
                        <div className="form-group">
                            <label htmlFor="startHour">Start Hour (Offline)</label>
                            <input
                                id="startHour"
                                name="startHour"
                                type="time"
                                value={settings.start_hour}
                                onChange={(e) => setSettings(prev => ({ ...prev, start_hour: e.target.value }))}
                                required
                            />
                        </div>

                        <div className="form-group">
                            <label htmlFor="endHour">End Hour (Offline)</label>
                            <input
                                id="endHour"
                                name="endHour"
                                type="time"
                                value={settings.end_hour}
                                onChange={(e) => setSettings(prev => ({ ...prev, end_hour: e.target.value }))}
                                required
                            />
                        </div>

                        <div className="form-group">
                            <label htmlFor="timezone">Timezone</label>
                            <div className="select-with-icon">
                                <Globe size={18} />
                                <select
                                    id="timezone"
                                    name="timezone"
                                    value={settings.timezone}
                                    onChange={(e) => setSettings(prev => ({ ...prev, timezone: e.target.value }))}
                                >
                                    <option value="UTC">UTC (Coordinated Universal Time)</option>
                                    <option value="GMT">GMT (Greenwich Mean Time)</option>
                                    <option value="EST">EST (Eastern Standard Time)</option>
                                    <option value="PST">PST (Pacific Standard Time)</option>
                                </select>
                            </div>
                        </div>
                    </div>
                </div>

                {status && (
                    <div className={`status-banner ${status.type}`}>
                        {status.msg}
                    </div>
                )}

                <button type="submit" className="save-btn" disabled={saving}>
                    {saving ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}
                    {saving ? 'Saving...' : 'Save Settings'}
                </button>
            </form>
        </div>
    );
};

import { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import {
    Megaphone,
    Plus,
    Trash2,
    Clock,
    Loader2
} from 'lucide-react';
import ReactQuill from 'react-quill-new';
import 'react-quill-new/dist/quill.snow.css';
import DOMPurify from 'dompurify';
import { toast } from 'react-hot-toast';
import { API_URL } from '../../lib/api';
import './BroadcastManager.css';

interface Broadcast {
    id: string;
    title: string;
    content: string;
    target_audience: string;
    created_at: string;
    expires_at: string | null;
    admin: {
        username: string;
    };
}

export const BroadcastManager = () => {
    const { session } = useAuth();
    const [broadcasts, setBroadcasts] = useState<Broadcast[]>([]);
    const [loading, setLoading] = useState(true);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isDeleting, setIsDeleting] = useState<string | null>(null);
    const [showModal, setShowModal] = useState(false);
    const [newBroadcast, setNewBroadcast] = useState({
        title: '',
        content: '',
        target_audience: 'all',
        expires_in_hours: '24'
    });

    useEffect(() => {
        fetchBroadcasts();
    }, [session]);

    const fetchBroadcasts = async () => {
        if (!session?.access_token) return;
        try {
            const res = await fetch(`${API_URL}/api/admin/broadcasts`, {
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                }
            });
            const data = await res.json();
            setBroadcasts(data);
        } catch (err) {
            console.error('Failed to fetch broadcasts:', err);
            toast.error('Failed to load broadcasts');
        } finally {
            setLoading(false);
        }
    };

    const handleCreate = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!session?.access_token) return;

        setIsSubmitting(true);
        try {
            const expiresAt = new Date();
            expiresAt.setHours(expiresAt.getHours() + parseInt(newBroadcast.expires_in_hours));

            const res = await fetch(`${API_URL}/api/admin/broadcasts`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({
                    ...newBroadcast,
                    expires_at: expiresAt.toISOString()
                })
            });

            if (res.ok) {
                const created = await res.json();
                setBroadcasts(prev => [created, ...prev]);
                setShowModal(false);
                setNewBroadcast({ title: '', content: '', target_audience: 'all', expires_in_hours: '24' });
                toast.success('Broadcast sent successfully');
            } else {
                toast.error('Failed to send broadcast');
            }
        } catch (err) {
            console.error('Failed to create broadcast:', err);
            toast.error('An error occurred');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm('Are you sure you want to delete this broadcast?')) return;
        if (!session?.access_token) return;

        setIsDeleting(id);
        try {
            const res = await fetch(`${API_URL}/api/admin/broadcasts/${id}`, {
                method: 'DELETE',
                headers: { 'Authorization': `Bearer ${session.access_token}` }
            });

            if (res.ok) {
                setBroadcasts(prev => prev.filter(b => b.id !== id));
                toast.success('Broadcast deleted');
            } else {
                toast.error('Failed to delete broadcast');
            }
        } catch (err) {
            console.error('Failed to delete broadcast:', err);
            toast.error('An error occurred while deleting');
        } finally {
            setIsDeleting(null);
        }
    };

    return (
        <div className="broadcast-manager">
            <div className="page-header">
                <div className="header-title">
                    <Megaphone className="header-icon" />
                    <div>
                        <h2>Broadcast Messages</h2>
                        <p>Send announcements to all active users</p>
                    </div>
                </div>
                <button className="create-btn" onClick={() => setShowModal(true)}>
                    <Plus size={18} /> New Broadcast
                </button>
            </div>

            <div className="broadcast-grid">
                {loading ? (
                    <div className="col-span-full flex justify-center py-20">
                        <Loader2 className="animate-spin text-primary" size={32} />
                    </div>
                ) : broadcasts.length === 0 ? (
                    <div className="empty-state">
                        <Megaphone size={48} />
                        <h3>No broadcasts yet</h3>
                        <p>Start by creating your first global announcement.</p>
                    </div>
                ) : (
                    broadcasts.map(b => (
                        <div key={b.id} className="broadcast-card">
                            <div className="card-header">
                                <span className="audience-tag">{b.target_audience}</span>
                                <button 
                                    className="delete-btn" 
                                    onClick={() => handleDelete(b.id)}
                                    disabled={isDeleting === b.id}
                                >
                                    {isDeleting === b.id ? <Loader2 size={16} className="animate-spin" /> : <Trash2 size={16} />}
                                </button>
                            </div>
                            <h3>{b.title}</h3>
                            <div
                                className="content"
                                dangerouslySetInnerHTML={{ __html: DOMPurify.sanitize(b.content) }}
                            />
                            <div className="card-footer">
                                <span className="admin-name">By {b.admin.username}</span>
                                <span className="date">
                                    <Clock size={12} />
                                    {new Date(b.created_at).toLocaleDateString()}
                                </span>
                            </div>
                        </div>
                    ))
                )}
            </div>

            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <h3>Create New Broadcast</h3>
                        <form onSubmit={handleCreate}>
                            <div className="form-group">
                                <label htmlFor="broadcastTitle">Title</label>
                                <input
                                    id="broadcastTitle"
                                    name="broadcastTitle"
                                    type="text"
                                    required
                                    value={newBroadcast.title}
                                    onChange={e => setNewBroadcast({ ...newBroadcast, title: e.target.value })}
                                    placeholder="Enter title..."
                                />
                            </div>
                            <div className="form-group quill-group">
                                <label htmlFor="broadcastContent">Content</label>
                                <div id="broadcastContent">
                                    <ReactQuill
                                        theme="snow"
                                        value={newBroadcast.content}
                                        onChange={content => setNewBroadcast({ ...newBroadcast, content })}
                                        placeholder="Enter announcement message..."
                                    />
                                </div>
                            </div>
                            <div className="form-row">
                                <div className="form-group">
                                    <label htmlFor="targetAudience">Audience</label>
                                    <select
                                        id="targetAudience"
                                        name="targetAudience"
                                        value={newBroadcast.target_audience}
                                        onChange={e => setNewBroadcast({ ...newBroadcast, target_audience: e.target.value })}
                                    >
                                        <option value="all">All Users</option>
                                        <option value="pro">Pro Only</option>
                                        <option value="free">Free Only</option>
                                    </select>
                                </div>
                                <div className="form-group">
                                    <label htmlFor="expiresIn">Expires In</label>
                                    <select
                                        id="expiresIn"
                                        name="expiresIn"
                                        value={newBroadcast.expires_in_hours}
                                        onChange={e => setNewBroadcast({ ...newBroadcast, expires_in_hours: e.target.value })}
                                    >
                                        <option value="1">1 Hour</option>
                                        <option value="6">6 Hours</option>
                                        <option value="24">24 Hours</option>
                                        <option value="168">7 Days</option>
                                    </select>
                                </div>
                            </div>
                            <div className="modal-actions">
                                <button type="button" className="cancel-btn" onClick={() => setShowModal(false)}>Cancel</button>
                                <button 
                                    type="submit" 
                                    className="submit-btn flex items-center justify-center gap-2" 
                                    disabled={!newBroadcast.title || !newBroadcast.content || newBroadcast.content === '<p><br></p>' || isSubmitting}
                                >
                                    {isSubmitting && <Loader2 size={16} className="animate-spin" />}
                                    Send Broadcast
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

import { useState, useEffect } from 'react';
import { toast } from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';
import {
    Clock,
    ArrowUpCircle,
    Loader2,
    CheckCircle,
    XCircle
} from 'lucide-react';
import { API_URL } from '../../lib/api';
import './LimitRequestsPage.css';

interface LimitRequest {
    id: string;
    user_id: string;
    requested_limit: number;
    reason: string;
    status: 'pending' | 'approved' | 'rejected';
    admin_note: string | null;
    created_at: string;
    user: {
        username: string;
        email: string;
        full_name: string;
        plan_tier: string;
        daily_deposit_limit: number | null;
    };
}

export const LimitRequestsPage = () => {
    const { session } = useAuth();
    const [requests, setRequests] = useState<LimitRequest[]>([]);
    const [loading, setLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState<'pending' | 'approved' | 'rejected'>('pending');
    const [processingId, setProcessingId] = useState<string | null>(null);

    useEffect(() => {
        fetchRequests();
    }, [session, statusFilter]);

    const fetchRequests = async () => {
        if (!session?.access_token) return;
        setLoading(true);

        try {
            const res = await fetch(`${API_URL}/api/admin/limit-requests?status=${statusFilter}`, {
                headers: {
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                }
            });

            if (!res.ok) throw new Error('Failed to fetch requests');
            const data = await res.json();
            setRequests(data);
        } catch (err) {
            console.error('Fetch error:', err);
            toast.error('Failed to load limit requests');
        } finally {
            setLoading(false);
        }
    };

    const handleProcessRequest = async (id: string, status: 'approved' | 'rejected', note: string = '') => {
        if (!session?.access_token) return;
        setProcessingId(id);

        try {
            const res = await fetch(`${API_URL}/api/admin/limit-requests/${id}`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({ status, admin_note: note })
            });

            if (!res.ok) throw new Error('Failed to process request');

            toast.success(`Request ${status} successfully`);
            setRequests(prev => prev.filter(r => r.id !== id));
        } catch (err) {
            toast.error('Failed to process request');
        } finally {
            setProcessingId(null);
        }
    };

    const formatDate = (dateStr: string) => {
        return new Date(dateStr).toLocaleString('en-US', {
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    return (
        <div className="limit-requests-page">
            <div className="page-header">
                <div className="title-section">
                    <h2>Limit Increase Requests</h2>
                    <p className="subtitle">Review and manage custom daily transaction limits</p>
                </div>

                <div className="filter-tabs">
                    <button 
                        className={statusFilter === 'pending' ? 'active' : ''} 
                        onClick={() => setStatusFilter('pending')}
                    >
                        Pending
                    </button>
                    <button 
                        className={statusFilter === 'approved' ? 'active' : ''} 
                        onClick={() => setStatusFilter('approved')}
                    >
                        Approved
                    </button>
                    <button 
                        className={statusFilter === 'rejected' ? 'active' : ''} 
                        onClick={() => setStatusFilter('rejected')}
                    >
                        Rejected
                    </button>
                </div>
            </div>

            <div className="requests-container">
                {loading ? (
                    <div className="loading-state">
                        <Loader2 className="animate-spin" size={32} />
                        <p>Loading requests...</p>
                    </div>
                ) : requests.length === 0 ? (
                    <div className="empty-state">
                        <Clock size={48} className="text-gray-600 mb-4" />
                        <h3>No {statusFilter} requests</h3>
                        <p>All clear! There are no {statusFilter} limit increase requests to show.</p>
                    </div>
                ) : (
                    <div className="requests-grid">
                        {requests.map(request => (
                            <div key={request.id} className="request-card">
                                <div className="card-header">
                                    <div className="user-info">
                                        <div className="avatar-mini">
                                            {request.user.username[0].toUpperCase()}
                                        </div>
                                        <div>
                                            <span className="username">{request.user.username}</span>
                                            <span className="email">{request.user.email}</span>
                                        </div>
                                    </div>
                                    <div className={`plan-badge ${request.user.plan_tier}`}>
                                        {request.user.plan_tier}
                                    </div>
                                </div>

                                <div className="limit-comparison">
                                    <div className="limit-item">
                                        <span className="label">Current Limit</span>
                                        <span className="value">${(request.user.daily_deposit_limit || 0).toLocaleString()}</span>
                                    </div>
                                    <div className="limit-arrow">
                                        <ArrowUpCircle className="text-primary" size={20} />
                                    </div>
                                    <div className="limit-item">
                                        <span className="label">Requested</span>
                                        <span className="value requested">${request.requested_limit.toLocaleString()}</span>
                                    </div>
                                </div>

                                <div className="reason-box">
                                    <span className="label">Reason for Request</span>
                                    <p>{request.reason || 'No reason provided.'}</p>
                                </div>

                                <div className="card-footer">
                                    <span className="timestamp">{formatDate(request.created_at)}</span>

                                    {statusFilter === 'pending' && (
                                        <div className="action-buttons">
                                            <button 
                                                className="btn-reject"
                                                onClick={() => handleProcessRequest(request.id, 'rejected')}
                                                disabled={!!processingId}
                                            >
                                                {processingId === request.id ? <Loader2 className="animate-spin" size={16} /> : <XCircle size={16} />}
                                                Reject
                                            </button>
                                            <button 
                                                className="btn-approve"
                                                onClick={() => handleProcessRequest(request.id, 'approved')}
                                                disabled={!!processingId}
                                            >
                                                {processingId === request.id ? <Loader2 className="animate-spin" size={16} /> : <CheckCircle size={16} />}
                                                Approve
                                            </button>
                                        </div>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
};

import { useState, useEffect } from 'react';
import { toast } from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';
import { API_URL } from '../../lib/api';
import { adService, type Ad } from '../../services/ads';
import { Card } from '../../components/common/Card';
import { Button } from '../../components/common/Button';
import { Check, X, ExternalLink, Loader2, Target } from 'lucide-react';
import SecureImage from '../../components/common/SecureImage';

export const ManageAds = () => {
    const { session } = useAuth();
    const [ads, setAds] = useState<Ad[]>([]);
    const [loading, setLoading] = useState(true);
    const [actionLoading, setActionLoading] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'pending' | 'approved' | 'all'>('pending');

    useEffect(() => {
        fetchAds();
    }, [activeTab, session]);

    const fetchAds = async () => {
        if (!session?.access_token) return;
        setLoading(true);
        try {
            const statusFilter = activeTab === 'all' ? undefined : activeTab;
            const params = new URLSearchParams();
            if (statusFilter) params.append('status', statusFilter);

            const res = await fetch(`${API_URL}/api/ads/moderation?${params}`, {
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                }
            });
            if (res.ok) {
                const data = await res.json();
                setAds(data);
            } else {
                throw new Error(`HTTP error! status: ${res.status}`);
            }
        } catch (error) {
            console.error('Failed to fetch ads:', error);
            toast.error('Failed to load ads');
        } finally {
            setLoading(false);
        }
    };

    const handleAction = async (id: string, action: 'approved' | 'rejected') => {
        setActionLoading(id);
        try {
            await adService.updateAdStatus(id, action);
            toast.success(`Ad ${action} successfully`);

            // Optimistic update
            setAds(prev => prev.filter(ad => ad.id !== id));
        } catch (error) {
            console.error(error);
            toast.error('Failed to update status');
        } finally {
            setActionLoading(null);
        }
    };

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'approved': return 'text-green-400 border-green-400/20 bg-green-400/10';
            case 'rejected': return 'text-red-400 border-red-400/20 bg-red-400/10';
            case 'pending': return 'text-yellow-400 border-yellow-400/20 bg-yellow-400/10';
            default: return 'text-gray-400 border-gray-400/20 bg-gray-400/10';
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl font-bold flex items-center gap-2">
                        <Target className="text-primary" />
                        Ad Moderation
                    </h1>
                    <p className="text-gray-400">Review and manage user-created advertisements</p>
                </div>

                <div className="flex bg-white/5 p-1 rounded-lg border border-white/10 overflow-x-auto no-scrollbar">
                    <button
                        onClick={() => setActiveTab('pending')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-colors whitespace-nowrap ${activeTab === 'pending' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}
                    >
                        Pending Review
                    </button>
                    <button
                        onClick={() => setActiveTab('approved')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-colors whitespace-nowrap ${activeTab === 'approved' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}
                    >
                        Live Ads
                    </button>
                    <button
                        onClick={() => setActiveTab('all')}
                        className={`px-4 py-2 rounded-md text-sm font-medium transition-colors whitespace-nowrap ${activeTab === 'all' ? 'bg-primary text-white' : 'text-gray-400 hover:text-white'}`}
                    >
                        All History
                    </button>
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center py-20">
                    <Loader2 className="animate-spin text-primary" size={32} />
                </div>
            ) : (
                <div className="grid gap-6">
                    {ads.length === 0 ? (
                        <div className="text-center py-20 text-gray-500">
                            <Target size={48} className="mx-auto mb-4 opacity-20" />
                            <p>No advertisements found in this category.</p>
                        </div>
                    ) : (
                        ads.map((ad: any) => (
                            <Card key={ad.id} variant="glass" className="p-6">
                                <div className="flex flex-col md:flex-row gap-6">
                                    {/* Image Preview */}
                                    <div className="w-full md:w-48 h-32 bg-black/40 rounded-lg flex items-center justify-center overflow-hidden border border-white/10 shrink-0">
                                        {ad.image_url ? (
                                            <SecureImage src={ad.image_url} alt="Ad Preview" className="w-full h-full object-cover" fallbackType="card" />
                                        ) : (
                                            <span className="text-xs text-gray-500">No Image</span>
                                        )}
                                    </div>

                                    {/* Content */}
                                    <div className="flex-1 min-w-0 space-y-3">
                                        <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
                                            <div className="min-w-0">
                                                <h3 className="text-lg font-bold truncate">{ad.title}</h3>
                                                <div className="flex flex-wrap items-center gap-2 mt-1">
                                                    <span className={`text-xs px-2 py-0.5 rounded border ${getStatusColor(ad.status)} capitalize`}>
                                                        {ad.status}
                                                    </span>
                                                    <span className="text-xs text-gray-500 truncate">
                                                        by {ad.profiles?.full_name || ad.profiles?.email || 'Unknown User'}
                                                    </span>
                                                    <span className="text-xs text-gray-500 whitespace-nowrap">
                                                        • {new Date(ad.created_at).toLocaleDateString()}
                                                    </span>
                                                </div>
                                            </div>

                                            {/* Actions */}
                                            {ad.status === 'pending' && (
                                                <div className="flex gap-2">
                                                    <Button
                                                        size="sm"
                                                        className="bg-green-500/20 text-green-400 hover:bg-green-500/30 border-green-500/50 flex-1 sm:flex-none"
                                                        onClick={() => handleAction(ad.id, 'approved')}
                                                        disabled={actionLoading === ad.id}
                                                    >
                                                        {actionLoading === ad.id ? <Loader2 size={16} className="animate-spin mr-1" /> : <Check size={16} className="mr-1" />} Approve
                                                    </Button>
                                                    <Button
                                                        size="sm"
                                                        className="bg-red-500/20 text-red-400 hover:bg-red-500/30 border-red-500/50 flex-1 sm:flex-none"
                                                        onClick={() => handleAction(ad.id, 'rejected')}
                                                        disabled={actionLoading === ad.id}
                                                    >
                                                        {actionLoading === ad.id ? <Loader2 size={16} className="animate-spin mr-1" /> : <X size={16} className="mr-1" />} Reject
                                                    </Button>
                                                </div>
                                            )}
                                            {ad.status === 'approved' && (
                                                <Button
                                                    size="sm"
                                                    className="bg-red-500/20 text-red-400 hover:bg-red-500/30 border-red-500/50 w-full sm:w-auto"
                                                    onClick={() => handleAction(ad.id, 'rejected')}
                                                    disabled={actionLoading === ad.id}
                                                >
                                                    {actionLoading === ad.id ? <Loader2 size={16} className="animate-spin mr-2" /> : null} Revoke
                                                </Button>
                                            )}
                                        </div>

                                        <p className="text-gray-300 break-words">{ad.content}</p>

                                        {ad.link_url && (
                                            <a
                                                href={ad.link_url}
                                                target="_blank"
                                                rel="noopener noreferrer"
                                                className="inline-flex items-center gap-1 text-primary hover:text-primary/80 text-sm"
                                            >
                                                <ExternalLink size={14} /> {ad.link_url}
                                            </a>
                                        )}
                                    </div>
                                </div>
                            </Card>
                        ))
                    )}
                </div>
            )}
        </div>
    );
};

import { useState, useEffect } from 'react';
import { toast } from 'react-hot-toast';
import { useAuth } from '../../context/AuthContext';
import {
    Search,
    UserCheck,
    UserX,
    ChevronLeft,
    ChevronRight,
    FileText,
    Filter,
    Loader2,
    Zap,
    X
} from 'lucide-react';
import { API_URL } from '../../lib/api';
import SecureImage from '../../components/common/SecureImage';
import './UserManagement.css';

interface User {
    id: string;
    username: string;
    email: string;
    full_name: string;
    avatar_url: string;
    role: string;
    status: string;
    is_online: boolean;
    last_seen: string;
    created_at: string;
    notesCount: number;
    daily_deposit_limit: number | null;
    plan_tier: string;
}

interface Pagination {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
}

export const UserManagement = () => {
    const { session } = useAuth();
    const [users, setUsers] = useState<User[]>([]);
    const [pagination, setPagination] = useState<Pagination>({
        page: 1,
        limit: 20,
        total: 0,
        totalPages: 0
    });
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('');
    const [loading, setLoading] = useState(true);
    const [actionLoading, setActionLoading] = useState<string | null>(null);
    const [selectedUser, setSelectedUser] = useState<User | null>(null);
    const [isLimitModalOpen, setIsLimitModalOpen] = useState(false);
    const [newLimit, setNewLimit] = useState<string>('');

    useEffect(() => {
        fetchUsers();
    }, [session, pagination.page, statusFilter]);

    useEffect(() => {
        const debounce = setTimeout(() => {
            if (pagination.page === 1) {
                fetchUsers();
            } else {
                setPagination(prev => ({ ...prev, page: 1 }));
            }
        }, 300);
        return () => clearTimeout(debounce);
    }, [search]);

    const fetchUsers = async () => {
        if (!session?.access_token) return;
        setLoading(true);

        try {
            const params = new URLSearchParams({
                page: pagination.page.toString(),
                limit: pagination.limit.toString(),
                ...(search && { search }),
                ...(statusFilter && { status: statusFilter })
            });

            const res = await fetch(`${API_URL}/api/admin/users?${params}`, {
                headers: { 
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                }
            });

            if (!res.ok) throw new Error('Failed to fetch users');

            const data = await res.json() || {};
            setUsers(data.users || []);
            setPagination(data.pagination || {
                page: 1,
                limit: 20,
                total: 0,
                totalPages: 0
            });
        } catch (err) {
            console.error('Failed to fetch users:', err);
            toast.error('Failed to load users');
        } finally {
            setLoading(false);
        }
    };

    const updateUserStatus = async (userId: string, newStatus: 'active' | 'suspended') => {
        if (!session?.access_token) return;
        setActionLoading(userId);

        try {
            const res = await fetch(`${API_URL}/api/admin/users/${userId}/status`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`,
                    'Accept': 'application/json'
                },
                body: JSON.stringify({ status: newStatus })
            });

            if (!res.ok) {
                const error = await res.json();
                throw new Error(error.error || 'Failed to update user');
            }

            // Update local state
            setUsers(prev => prev.map(u =>
                u.id === userId ? { ...u, status: newStatus } : u
            ));
        } catch (err) {
            console.error('Failed to update user:', err);
            toast.error(err instanceof Error ? err.message : 'Failed to update user');
        } finally {
            setActionLoading(null);
        }
    };

    const handleUpdateLimit = async () => {
        if (!selectedUser || !session?.access_token) return;
        setActionLoading(selectedUser.id);

        try {
            const res = await fetch(`${API_URL}/api/admin/users/${selectedUser.id}/limit`, {
                method: 'PUT',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({ daily_limit: parseFloat(newLimit) })
            });

            if (!res.ok) throw new Error('Failed to update limit');

            setUsers(prev => prev.map(u =>
                u.id === selectedUser.id ? { ...u, daily_deposit_limit: parseFloat(newLimit) } : u
            ));
            toast.success('Limit updated successfully');
            setIsLimitModalOpen(false);
        } catch (err) {
            toast.error('Failed to update limit');
        } finally {
            setActionLoading(null);
        }
    };

    const formatDate = (dateStr: string) => {
        return new Date(dateStr).toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'short',
            day: 'numeric'
        });
    };

    return (
        <div className="user-management">
            <div className="page-header">
                <h2>User Management</h2>
                <span className="total-count">{pagination.total} users</span>
            </div>

            {/* Filters */}
            <div className="filters-bar">
                <div className="search-box">
                    <Search size={18} />
                    <input
                        id="user-search"
                        name="search"
                        type="text"
                        placeholder="Search by username, email, or name..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        aria-label="Search users by username, email, or name"
                    />
                </div>
                <div className="filter-group">
                    <Filter size={18} />
                    <select
                        id="user-status-filter"
                        name="status"
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                        aria-label="Filter by status"
                    >
                        <option value="">All Status</option>
                        <option value="active">Active</option>
                        <option value="suspended">Suspended</option>
                    </select>
                </div>
            </div>

            {/* Users Table */}
            <div className="users-table-container">
                <table className="users-table">
                    <thead>
                        <tr>
                            <th>User</th>
                            <th>Email</th>
                            <th>Role</th>
                            <th>Status</th>
                            <th>Notes</th>
                            <th>Joined</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr>
                                <td colSpan={7} className="loading-row">
                                    <div className="loader-small" />
                                    Loading users...
                                </td>
                            </tr>
                        ) : users.length === 0 ? (
                            <tr>
                                <td colSpan={7} className="empty-row">
                                    No users found
                                </td>
                            </tr>
                        ) : (
                            users?.map(user => (
                                <tr key={user.id}>
                                    <td className="user-cell">
                                        <div className="user-info">
                                            {user.avatar_url ? (
                                                <SecureImage src={user.avatar_url} alt={user.username} fallbackType="profile" />
                                            ) : (
                                                <div className="avatar-placeholder">
                                                    {user.username?.[0]?.toUpperCase() || '?'}
                                                </div>
                                            )}
                                            <div className="user-details min-w-0">
                                                <span className="username truncate">
                                                    {user.username}
                                                    {user.is_online && <span className="online-dot flex-shrink-0" />}
                                                </span>
                                                <span className="fullname truncate text-xs text-gray-500">{user.full_name}</span>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="max-w-[150px] md:max-w-[200px]">
                                        <div className="truncate" title={user.email}>{user.email}</div>
                                    </td>
                                    <td>
                                        <span className={`role-badge ${user.role}`}>
                                            {user.role}
                                        </span>
                                    </td>
                                    <td>
                                        <span className={`status-badge ${user.status}`}>
                                            {user.status}
                                        </span>
                                    </td>
                                    <td>
                                        <span className="notes-count">
                                            <FileText size={14} />
                                            {user.notesCount}
                                        </span>
                                    </td>
                                    <td className="date-cell">{formatDate(user.created_at)}</td>
                                    <td className="actions-cell">
                                        <div className="flex items-center gap-1">
                                            <button
                                                className="action-btn limit"
                                                onClick={() => {
                                                    setSelectedUser(user);
                                                    setNewLimit(user.daily_deposit_limit?.toString() || '');
                                                    setIsLimitModalOpen(true);
                                                }}
                                                title="Manage Limits"
                                            >
                                                <Zap size={16} />
                                            </button>
                                            
                                            {user.role !== 'admin' && (
                                                <>
                                                    {user.status === 'active' ? (
                                                        <button
                                                            className="action-btn suspend"
                                                            onClick={() => updateUserStatus(user.id, 'suspended')}
                                                            disabled={actionLoading === user.id}
                                                            title="Suspend user"
                                                        >
                                                            {actionLoading === user.id ? <Loader2 size={16} className="animate-spin" /> : <UserX size={16} />}
                                                        </button>
                                                    ) : (
                                                        <button
                                                            className="action-btn activate"
                                                            onClick={() => updateUserStatus(user.id, 'active')}
                                                            disabled={actionLoading === user.id}
                                                            title="Reactivate user"
                                                        >
                                                            {actionLoading === user.id ? <Loader2 size={16} className="animate-spin" /> : <UserCheck size={16} />}
                                                        </button>
                                                    )}
                                                </>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            {pagination.totalPages > 1 && (
                <div className="pagination">
                    <button
                        className="page-btn"
                        onClick={() => setPagination(p => ({ ...p, page: p.page - 1 }))}
                        disabled={pagination.page <= 1}
                    >
                        <ChevronLeft size={18} />
                        Previous
                    </button>
                    <span className="page-info">
                        Page {pagination.page} of {pagination.totalPages}
                    </span>
                    <button
                        className="page-btn"
                        onClick={() => setPagination(p => ({ ...p, page: p.page + 1 }))}
                        disabled={pagination.page >= pagination.totalPages}
                    >
                        Next
                        <ChevronRight size={18} />
                    </button>
                </div>
            )}

            {/* Limit Edit Modal */}
            {isLimitModalOpen && selectedUser && (
                <div className="modal-overlay" onClick={() => setIsLimitModalOpen(false)}>
                    <div className="modal-content limit-modal" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h3>Manage Limits: {selectedUser.username}</h3>
                            <button className="close-btn" onClick={() => setIsLimitModalOpen(false)}>
                                <X size={20} />
                            </button>
                        </div>
                        <div className="modal-body">
                            <div className="current-info mb-4 text-sm text-gray-400">
                                <p>Current Plan: <span className="capitalize text-white">{selectedUser.plan_tier}</span></p>
                                <p>Current Limit: <span className="text-white">${selectedUser.daily_deposit_limit?.toLocaleString() || 'Default'}</span></p>
                            </div>
                            
                            <div className="form-group mb-6">
                                <label className="block text-xs uppercase tracking-wider text-gray-500 mb-2">Daily Deposit Limit (USD)</label>
                                <div className="relative">
                                    <input
                                        type="number"
                                        value={newLimit}
                                        onChange={e => setNewLimit(e.target.value)}
                                        placeholder="e.g. 5000"
                                        className="w-full bg-gray-900 border border-gray-700 rounded-lg p-3 text-white focus:outline-none focus:border-primary"
                                    />
                                    <span className="absolute right-3 top-3 text-gray-400">$</span>
                                </div>
                                <p className="text-[10px] text-gray-500 mt-2 italic">Setting a custom limit will override the default plan limits for this user.</p>
                            </div>

                            <div className="modal-actions flex gap-3">
                                <button 
                                    className="flex-1 py-3 bg-gray-800 hover:bg-gray-700 rounded-lg transition-colors"
                                    onClick={() => setIsLimitModalOpen(false)}
                                >
                                    Cancel
                                </button>
                                <button 
                                    className="flex-1 py-3 bg-primary hover:bg-primary-dark rounded-lg font-bold transition-colors disabled:opacity-50"
                                    onClick={handleUpdateLimit}
                                    disabled={actionLoading === selectedUser.id}
                                >
                                    {actionLoading === selectedUser.id ? <Loader2 className="animate-spin mx-auto" size={20} /> : 'Save Changes'}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import { useState, useEffect, useRef } from 'react';
import { API_URL } from '../../lib/api';
import { Card } from '../../components/common/Card';
import { Button } from '../../components/common/Button';
import { Check, CreditCard, Loader2, Zap, X, Mail, Calendar, BadgeCheck } from 'lucide-react';
import { useSearchParams } from 'react-router-dom';
import { toast } from 'react-hot-toast';
import { supabase } from '../../lib/supabase';
import { supabaseSafe } from '../../lib/supabaseSafe';
import { useAuth } from '../../context/AuthContext';
import { formatCurrency, detectLocalCurrency } from '../../lib/CurrencyFormatter';

// Removed local Subscription interface as it is now provided by useAuth

export const Billing = () => {
    const { isPro, subscription, refreshProfile } = useAuth();
    const [searchParams] = useSearchParams();
    const [loading, setLoading] = useState(true);
    const [processing, setProcessing] = useState(false);
    const [showDetails, setShowDetails] = useState(false);
    const [paymentMethod, setPaymentMethod] = useState<'paystack' | 'fincra' | 'auto'>('auto');
    const [currency, setCurrency] = useState<string>(detectLocalCurrency());

    const fetchingRef = useRef(false);
    const isMounted = useRef(true);

    useEffect(() => {
        isMounted.current = true;
        checkSubscriptionStatus();

        // Handle redirect from Paystack
        const reference = searchParams.get('reference');
        // Paystack doesn't typically send 'success' param unless we add it, but it sends reference
        
        if (reference) {
            const method = (searchParams.get('method') as 'paystack' | 'fincra') || 'paystack';
            const cur = searchParams.get('currency') || 'NGN';
            syncSubscription(reference, method, cur);
        }
        
        return () => { isMounted.current = false; };
    }, [searchParams]);

    const [exchangeRate, setExchangeRate] = useState<number | null>(null);

    const checkSubscriptionStatus = async () => {
        if (fetchingRef.current) return;
        fetchingRef.current = true;

        await supabaseSafe('billing-status', async () => {
            const { data: sessionData } = await supabase.auth.getSession();
            const token = sessionData.session?.access_token;
            if (!token) return; 

            // Fetch Exchange Rate
            try {
                const rateResponse = await fetch(`${API_URL}/api/subscription/rate`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                const rateData = await rateResponse.json();
                if (rateData.rate && isMounted.current) {
                    setExchangeRate(rateData.rate);
                }
            } catch (err) {
                console.error('Failed to fetch exchange rate', err);
            }
            
            return { success: true };
        });
        
        if (isMounted.current) {
            setLoading(false);
            fetchingRef.current = false;
        }
    };

    const syncSubscription = async (reference: string, method: string = 'paystack', cur: string = 'NGN') => {
        setProcessing(true);
        try {
            const { data } = await supabase.auth.getSession();
            const resolvedToken = data.session?.access_token;

            const response = await fetch(`${API_URL}/api/subscription/sync`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${resolvedToken}`
                },
                body: JSON.stringify({ reference, method, currency: cur })
            });

            const dataRes = await response.json();
            if (dataRes.success) {
                toast.success('Successfully upgraded to Pro!');
                refreshProfile(); // Refresh global auth state
            } else {
                toast.error('Verification failed. Please contact support.');
            }
        } catch (error) {
            console.error('Sync error:', error);
            toast.error('Failed to verify subscription');
        } finally {
            // ALWAYS clean URL parameters to prevent infinite looping on page reload
            window.history.replaceState({}, '', '/dashboard/billing');
            setProcessing(false);
        }
    };

    const handleUpgrade = async (planType: string = 'PRO') => {
        setProcessing(true);
        try {
            const { data } = await supabase.auth.getSession();
            const resolvedToken = data.session?.access_token;

            const response = await fetch(`${API_URL}/api/subscription/create-checkout-session`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${resolvedToken}`
                },
                body: JSON.stringify({ 
                    planType, 
                    paymentMethod: paymentMethod === 'auto' ? null : paymentMethod,
                    currency 
                })
            });

            const dataRes = await response.json();
            if (dataRes.url) {
                console.log('Redirecting to Paystack:', dataRes.url);
                window.location.href = dataRes.url;
            } else {
                throw new Error('No checkout URL received');
            }
        } catch (error) {
            console.error('Upgrade error:', error);
            toast.error('Failed to start checkout');
            setProcessing(false);
        }
    };

    const handleCancel = async () => {
        if (!confirm('Are you sure you want to cancel your PRO subscription?')) return;
        
        setProcessing(true);
        try {
            const { data } = await supabase.auth.getSession();
            const resolvedToken = data.session?.access_token;

            const response = await fetch(`${API_URL}/api/subscription/cancel`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${resolvedToken}`
                }
            });

            const dataRes = await response.json();
            if (dataRes.success) {
                toast.success('Subscription canceled');
                refreshProfile(); // Refresh global auth state
                setShowDetails(false);
            } else {
                toast.error('Failed to cancel subscription');
            }
        } catch (error) {
            console.error('Cancel error:', error);
            toast.error('Failed to cancel');
        } finally {
            setProcessing(false);
        }
    };

    const handleManageSubscription = () => {
        setShowDetails(!showDetails);
    };

    if (loading && !processing) {
        return (
            <div className="flex items-center justify-center py-20">
                <Loader2 className="animate-spin text-primary" size={32} />
            </div>
        );
    }

    return (
        <div className="space-y-6 max-w-6xl mx-auto">
            <div className="space-y-1">
                <h1 className="text-3xl font-bold">Plan & Subscription</h1>
                <p className="text-gray-400">Manage your subscription and billing details</p>
            </div>

            <div className="flex flex-col md:flex-row gap-6">
                <div className="flex-1 space-y-4">
                    <h3 className="text-sm font-medium text-gray-400">Select Currency</h3>
                    <div className="flex flex-wrap gap-2">
                        {['USD', 'GBP', 'EUR', 'NGN'].map(cur => (
                            <button
                                key={cur}
                                onClick={() => {
                                    setCurrency(cur);
                                    if (cur !== 'NGN' && paymentMethod !== 'auto') setPaymentMethod('auto');
                                }}
                                className={`px-4 py-2 rounded-lg border transition-all ${currency === cur ? 'bg-primary border-primary text-white' : 'bg-white/5 border-white/10 text-gray-400 hover:border-white/30'}`}
                            >
                                {cur}
                            </button>
                        ))}
                    </div>
                </div>

                {currency === 'NGN' && (
                    <div className="flex-1 space-y-4">
                        <h3 className="text-sm font-medium text-gray-400">Payment Provider</h3>
                        <div className="grid grid-cols-2 gap-3">
                            <button
                                onClick={() => setPaymentMethod('paystack')}
                                className={`p-3 rounded-lg border-2 transition-all flex items-center justify-between ${paymentMethod === 'paystack' ? 'border-primary bg-primary/10' : 'border-white/5 bg-white/5 hover:border-white/20'}`}
                            >
                                <div className="text-left">
                                    <p className="font-bold text-sm">Paystack</p>
                                    <p className="text-[10px] text-gray-400">Card/Transfer</p>
                                </div>
                                {paymentMethod === 'paystack' && <Check size={12} className="text-primary" />}
                            </button>

                            <button
                                onClick={() => setPaymentMethod('fincra')}
                                className={`p-3 rounded-lg border-2 transition-all flex items-center justify-between ${paymentMethod === 'fincra' ? 'border-primary bg-primary/10' : 'border-white/5 bg-white/5 hover:border-white/20'}`}
                            >
                                <div className="text-left">
                                    <p className="font-bold text-sm">Fincra</p>
                                    <p className="text-[10px] text-gray-400">Fast Bank Transfer</p>
                                </div>
                                {paymentMethod === 'fincra' && <Check size={12} className="text-primary" />}
                            </button>
                        </div>
                    </div>
                )}
            </div>

            {processing && (
                <div className="bg-blue-500/10 border border-blue-500/20 text-blue-400 p-4 rounded-lg flex items-center gap-3">
                    <Loader2 className="animate-spin" size={20} />
                    Processing your subscription update...
                </div>
            )}

            <div className="grid md:grid-cols-3 gap-6">
                {/* Free Plan */}
