                        variant="secondary"
                        fullWidth
                        disabled={!isPro}
                        className={!isPro ? "opacity-50 cursor-default" : ""}
                    >
                        {!isPro ? 'Active' : 'Downgrade'}
                    </Button>
                </Card>

                {/* Pro Plan */}
                <Card className={`p-6 border-2 ${subscription?.plan_tier === 'pro' ? 'border-primary bg-primary/5' : 'border-white/5 relative group'}`}>
