                        <div className="absolute top-0 right-0 bg-primary text-white text-xs font-bold px-3 py-1 rounded-bl-lg">
                            ACTIVE
                        </div>
                    )}
                    {!isPro && <div className="absolute -inset-0.5 bg-gradient-to-r from-pink-600 to-purple-600 rounded-xl opacity-20 blur group-hover:opacity-40 transition duration-1000"></div>}
                    <div className="relative">
                        <h3 className="text-xl font-bold mb-2 flex items-center gap-2">
                            Pro Plan <Zap size={18} className="text-yellow-400 fill-yellow-400" />
                        </h3>
                        <div className="mb-4">
                            <div className="text-3xl font-bold">{formatCurrency(9.99, currency)} <span className="text-sm font-normal text-gray-400">/ month</span></div>
                            {currency === 'NGN' && exchangeRate && (
                                <div className="text-sm text-gray-400 mt-1">
                                    Approx. {formatCurrency(9.99 * exchangeRate, 'NGN')}
                                </div>
                            )}
                        </div>
                        <p className="text-gray-400 mb-6 text-sm">Unlock the full power of Note Standard.</p>

                        <ul className="space-y-3 mb-8">
                            <li className="flex items-center gap-2 text-sm">
                                <Check size={16} className="text-green-500" /> Unlimited Notes
                            </li>
                            <li className="flex items-center gap-2 text-sm">
                                <Check size={16} className="text-green-500" /> <b>0.5% Crypto Spread</b>
                            </li>
                            <li className="flex items-center gap-2 text-sm">
                                <Check size={16} className="text-green-500" /> 20% Discount on Fees
                            </li>
                            <li className="flex items-center gap-2 text-sm">
                                <Check size={16} className="text-green-500" /> Priority Support
                            </li>
                        </ul>

                        {subscription?.plan_tier === 'pro' ? (
                            <Button variant="secondary" fullWidth onClick={handleManageSubscription} disabled={processing}>
                                {processing ? <Loader2 className="animate-spin" /> : 'Manage'}
                            </Button>
                        ) : (
                            <Button
                                onClick={() => handleUpgrade('PRO')}
                                disabled={processing}
                                className="w-full bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 border-none text-white shadow-lg shadow-purple-900/20"
                            >
                                {processing ? <Loader2 className="animate-spin" /> : 'Upgrade Pro'}
                            </Button>
                        )}
                    </div>
                </Card>

                {/* Business Plan */}
                <Card className={`p-6 border-2 ${subscription?.plan_tier === 'business' ? 'border-primary bg-primary/5' : 'border-white/5 relative group'}`}>
                    {subscription?.plan_tier === 'business' && (
                        <div className="absolute top-0 right-0 bg-primary text-white text-xs font-bold px-3 py-1 rounded-bl-lg">
                            ENTERPRISE
                        </div>
                    )}
                    <div className="absolute -inset-0.5 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-xl opacity-20 blur group-hover:opacity-40 transition duration-1000"></div>
                    <div className="relative">
                        <h3 className="text-xl font-bold mb-2 flex items-center gap-2">
                            Business <BadgeCheck size={18} className="text-blue-400" />
                        </h3>
                        <div className="mb-4">
                            <div className="text-3xl font-bold">{formatCurrency(29.99, currency)} <span className="text-sm font-normal text-gray-400">/ month</span></div>
                            {currency === 'NGN' && exchangeRate && (
                                <div className="text-sm text-gray-400 mt-1">
                                    Approx. {formatCurrency(29.99 * exchangeRate, 'NGN')}
                                </div>
                            )}
                        </div>
                        <p className="text-gray-400 mb-6 text-sm">Maximum limits & premium tools for scale.</p>

                        <ul className="space-y-3 mb-8">
                            <li className="flex items-center gap-2 text-sm">
                                <Check size={16} className="text-green-500" /> All Pro Features
                            </li>
                            <li className="flex items-center gap-2 text-sm text-blue-400 font-bold">
                                <Check size={16} className="text-blue-500" /> 0.5% Crypto Spread
                            </li>
                            <li className="flex items-center gap-2 text-sm">
                                <Check size={16} className="text-green-500" /> 50% Discount on Fees
                            </li>
                            <li className="flex items-center gap-2 text-sm">
                                <Check size={16} className="text-green-500" /> Unlimited Team Members
                            </li>
                        </ul>

                        {subscription?.plan_tier === 'business' ? (
                            <Button variant="secondary" fullWidth onClick={handleManageSubscription} disabled={processing}>
                                {processing ? <Loader2 className="animate-spin" /> : 'Manage'}
                            </Button>
                        ) : (
                            <Button
                                onClick={() => handleUpgrade('BUSINESS')}
                                disabled={processing}
                                className="w-full bg-blue-600 hover:bg-blue-700 border-none text-white shadow-lg"
                            >
                                {processing ? <Loader2 className="animate-spin" /> : 'Get Business'}
                            </Button>
                        )}
                    </div>
                </Card>
            </div>

            {/* Subscription Details Panel */}
            {showDetails && subscription && (
                <Card variant="glass" className="p-6 border border-primary/20">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4 flex-wrap">
                        <h3 className="text-lg font-semibold flex items-center gap-2">
                            <BadgeCheck className="text-blue-400" size={20} />
                            Your {subscription.plan_tier} Subscription
                        </h3>
                        <button
                            onClick={() => setShowDetails(false)}
                            className="text-gray-400 hover:text-white transition-colors"
                        >
                            <X size={20} />
                        </button>
                    </div>

                    <div className="space-y-4">
                        <div className="flex items-center gap-3 p-3 bg-white/5 rounded-lg">
                            <Calendar size={18} className="text-gray-400" />
                            <div>
                                <p className="text-sm text-gray-400">Member since</p>
                                <p className="font-medium">{subscription.created_at ? new Date(subscription.created_at).toLocaleDateString('en-US', {
                                    year: 'numeric',
                                    month: 'long',
                                    day: 'numeric'
                                }) : 'N/A'}</p>
                            </div>
                        </div>

                        <div className="flex items-center gap-3 p-3 bg-white/5 rounded-lg">
                            <CreditCard size={18} className="text-gray-400" />
                            <div>
                                <p className="text-sm text-gray-400">Plan</p>
                                <p className="font-medium capitalize">{subscription.plan_tier}</p>
                            </div>
                        </div>

                        <div className="flex items-center gap-3 p-3 bg-white/5 rounded-lg">
                            <Check size={18} className="text-green-400" />
                            <div>
                                <p className="text-sm text-gray-400">Status</p>
                                <p className="font-medium text-green-400 capitalize">{subscription.status}</p>
                            </div>
                        </div>

                        <div className="mt-6 p-4 bg-orange-500/10 border border-orange-500/20 rounded-lg">
                            <div className="flex items-start gap-3">
                                <Mail size={20} className="text-orange-400 mt-0.5" />
                                <div>
                                    <h4 className="font-medium text-orange-400 mb-1">Manage Subscription</h4>
                                    <p className="text-sm text-gray-400 mb-3">
                                        You can cancel your subscription at any time. Your access will continue until the end of the billing period.
                                    </p>
                                    <button
                                        onClick={handleCancel}
                                        disabled={processing}
                                        className="inline-flex items-center gap-2 text-sm text-red-400 hover:text-red-300 font-medium transition-colors"
                                    >
                                        <X size={14} />
                                        {processing ? 'Processing...' : 'Cancel Subscription'}
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </Card>
            )}
            <div className="mt-8 p-4 rounded-lg bg-white/5 border border-white/10 flex items-start gap-4">
                <div className="p-2 bg-white/10 rounded-full">
                    <CreditCard size={20} className="text-gray-300" />
                </div>
                <div>
                    <h4 className="font-semibold text-white mb-1">Secure Interaction</h4>
                    <p className="text-sm text-gray-400">
                        All interactions are processed securely. We do not store your sensitive information.
                    </p>
                </div>
            </div>
        </div>
    );
};

import { useEffect, useState } from 'react';
import { Input } from '../../components/common/Input';
import { FeedNoteCard } from '../../components/dashboard/FeedNoteCard';
import { CommentModal } from '../../components/dashboard/CommentModal';
import { Search, Loader2 } from 'lucide-react';
import { supabase, safeCall } from '../../lib/supabaseSafe';
import { useAuth } from '../../context/AuthContext';

export const Feed = () => {
    const { user } = useAuth();
    const [notes, setNotes] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [activeNote, setActiveNote] = useState<any | null>(null);

    const fetchFeed = async () => {
        if (!user) return;
        setLoading(true);
        
        const result = await safeCall(
            `feed-${user.id}-${searchTerm}`,
            async () => {
                // Fetch public notes
                const query = supabase
                    .from('notes')
                    .select(`
                        *,
                        owner:profiles!owner_id (username, email, avatar_url, plan_tier, is_verified)
                    `)
                    .eq('is_private', false)
                    .order('created_at', { ascending: false });

                if (searchTerm) {
                    query.ilike('title', `%${searchTerm}%`);
                }

                const { data: notesData, error } = await query;
                if (error) throw error;

                if (notesData) {
                    // Fetch likes and comments counts for each note
                    const enhancedNotes = await Promise.all(notesData.map(async (note) => {
                        const [likesCount, commentsCount, userLike] = await Promise.all([
                            supabase.rpc('get_like_count', { p_note_id: note.id }),
                            supabase.rpc('get_comment_count', { p_note_id: note.id }),
                            supabase.from('likes').select('id').eq('note_id', note.id).eq('user_id', user.id).maybeSingle()
                        ]);

                        return {
                            ...note,
                            likes_count: likesCount.data || 0,
                            comments_count: commentsCount.data || 0,
                            user_has_liked: !!userLike.data
                        };
                    }));

                    return enhancedNotes;
                }
                return [];
            },
            { minDelay: 1000, fallback: [] }
        );

        setNotes(result || []);
        setLoading(false);
    };

    useEffect(() => {
        const timeoutId = setTimeout(() => {
            fetchFeed();
        }, 500);

        // Setup Realtime Subscriptions for counts
        // Use debounce to prevent excessive refetching from global events
        let debounceTimer: ReturnType<typeof setTimeout> | null = null;
        const debouncedRefetch = () => {
            if (debounceTimer) clearTimeout(debounceTimer);
            debounceTimer = setTimeout(() => fetchFeed(), 2000);
        };

        const commentChannel = supabase
            .channel('public-comments')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'comments' },
                () => debouncedRefetch()
            )
            .subscribe();

        const likeChannel = supabase
            .channel('public-likes')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'likes' },
                () => debouncedRefetch()
            )
            .subscribe();

        return () => {
            clearTimeout(timeoutId);
            if (debounceTimer) clearTimeout(debounceTimer);
            supabase.removeChannel(commentChannel);
            supabase.removeChannel(likeChannel);
        };
    }, [user, searchTerm]);

    return (
        <div className="space-y-6 max-w-4xl mx-auto">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="space-y-1">
                    <h1 className="text-3xl font-bold">Community Feed</h1>
                    <p className="text-gray-400">Discover public notes from other users</p>
                </div>
                <div className="w-full md:w-72">
                    <Input
                        id="feed-search"
                        name="feedSearch"
                        icon={Search}
                        placeholder="Search public notes..."
                        className="bg-[#121212]"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
            </div>

            {loading ? (
                <div className="flex items-center justify-center py-20">
                    <Loader2 className="animate-spin text-primary" size={32} />
                </div>
            ) : notes.length === 0 ? (
                <div className="text-center py-20 space-y-3">
                    <div className="text-gray-500">No public notes found yet.</div>
                    <div className="text-sm text-gray-600">Be the first to share a note publicly!</div>
                </div>
            ) : (
                <div className="space-y-4">
                    {notes.map((note) => (
                        <FeedNoteCard
                            key={note.id}
                            note={note}
                            onCommentClick={setActiveNote}
                        />
                    ))}
                </div>
            )}

            <CommentModal
                isOpen={!!activeNote}
                onClose={() => setActiveNote(null)}
                note={activeNote}
            />
        </div>
    );
};
